export const ARTICLES_16: Article[] = [
  { id: 'ccyc-art-2277', lawId: 'codigo-civil-comercial', number: '2277', order: 2277, title: "Apertura de la sucesión", text: "Apertura de la sucesión. La muerte real o presunta de una persona causa la apertura de su sucesión y la transmisión de su herencia a las personas llamadas a sucederle por el testamento o por la ley. Si el testamento dispone sólo parcialmente de los bienes, el resto de la herencia se defiere por la ley. La herencia comprende todos los derechos y obligaciones del causante que no se extinguen por su fallecimiento.", plainLanguageExplanation: "Establece el régimen de apertura de la sucesión. La muerte real o presunta de una persona causa la apertura de su sucesión y la transmisión de su herencia a las personas llamadas a sucederle por el testamento o por la ley.", practicalEffects: ['En la práctica, este artículo rige apertura de la sucesión. La muerte real o presunta de una persona causa la apertura de su sucesión y la transmisión de su herencia a las personas llamadas a sucederle por el testamento o por la ley.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['apertura', 'sucesin', 'articulo 2277'], segments: [], amendments: [] },
  { id: 'ccyc-art-2278', lawId: 'codigo-civil-comercial', number: '2278', order: 2278, title: "Heredero y legatario", text: "Heredero y legatario. Concepto. Se denomina heredero a la persona a quien se transmite la universalidad o una parte indivisa de la herencia; legatario, al que recibe un bien particular o un conjunto de ellos.", plainLanguageExplanation: "Establece el régimen de heredero y legatario. Concepto.", practicalEffects: ['En la práctica, este artículo rige heredero y legatario. Concepto.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['heredero', 'legatario', 'articulo 2278'], segments: [], amendments: [] },
  { id: 'ccyc-art-2279', lawId: 'codigo-civil-comercial', number: '2279', order: 2279, title: "Personas que pueden suceder", text: "Personas que pueden suceder. Pueden suceder al causante: a) las personas humanas existentes al momento de su muerte; b) las concebidas en ese momento que nazcan con vida; c) las nacidas después de su muerte mediante técnicas de reproducción humana asistida, con los requisitos previstos en el artículo 561; d) las personas jurídicas existentes al tiempo de su muerte y las fundaciones creadas por su testamento.", plainLanguageExplanation: "Establece el régimen de personas que pueden suceder. Pueden suceder al causante: a) las personas humanas existentes al momento de su muerte; b) las concebidas en ese momento que nazcan con vida; c) las nacidas después de su muerte mediante técnicas de reproducción humana asistida, con los requisitos previstos en el artículo 561; d)", practicalEffects: ['En la práctica, este artículo rige personas que pueden suceder. Pueden suceder al causante: a) las personas humanas existentes al momento de su muerte; b) las concebidas en ese momento que nazcan con vida; c) las n'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['personas', 'pueden', 'suceder', 'articulo 2279'], segments: [], amendments: [] },
  { id: 'ccyc-art-2280', lawId: 'codigo-civil-comercial', number: '2280', order: 2280, title: "Situación de los herederos", text: "Situación de los herederos. Desde la muerte del causante, los herederos tienen todos los derechos y acciones de aquél de manera indivisa, con excepción de los que no son transmisibles por sucesión, y continúan en la posesión de lo que el causante era poseedor. Si están instituidos bajo condición suspensiva, están en esa situación a partir del cumplimiento de la condición, sin perjuicio de las medidas conservatorias que corresponden. En principio, responden por las deudas del causante con los bienes que reciben, o con su valor en caso de haber sido enajenados. CAPITULO 2 Indignidad", plainLanguageExplanation: "Establece el régimen de situación de los herederos. Desde la muerte del causante, los herederos tienen todos los derechos y acciones de aquél de manera indivisa, con excepción de los que no son transmisibles por sucesión, y continúan en la posesión de lo que el causante era poseedor.", practicalEffects: ['En la práctica, este artículo rige situación de los herederos. Desde la muerte del causante, los herederos tienen todos los derechos y acciones de aquél de manera indivisa, con excepción de los que no son transmis'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['situacin', 'herederos', 'articulo 2280'], segments: [], amendments: [] },
  { id: 'ccyc-art-2281', lawId: 'codigo-civil-comercial', number: '2281', order: 2281, title: "Causas de indignidad", text: "Causas de indignidad. Son indignos de suceder: a) los autores, cómplices o partícipes de delito doloso contra la persona, el honor, la integridad sexual, la libertad o la propiedad del causante, o de sus descendientes, ascendientes, cónyuge, conviviente o hermanos. Esta causa de indignidad no se cubre por la extinción de la acción penal ni por la de la pena; b) los que hayan maltratado gravemente al causante, u ofendido gravemente su memoria; c) los que hayan acusado o denunciado al causante por un delito penado con prisión o reclusión, excepto que la víctima del delito sea el acusador, su cónyuge o conviviente, su descendiente, ascendiente o hermano, o haya obrado en cumplimiento de un deber legal; d) los que omiten la denuncia de la muerte dolosa del causante, dentro de un mes de ocurrida, excepto que antes de ese término la justicia proceda en razón de otra denuncia o de oficio. Esta causa de indignidad no alcanza a las personas incapaces ni con capacidad restringida, ni a los descendientes, ascendientes, cónyuge y hermanos del homicida o de su cómplice; e) los parientes o el cónyuge que no hayan suministrado al causante los alimentos debidos, o no lo hayan recogido en establecimiento adecuado si no podía valerse por sí mismo; f) el padre extramatrimonial que no haya reconocido voluntariamente al causante durante su menor edad; g) el padre o la madre del causante que haya sido privado de la responsabilidad parental; h) los que hayan inducido o coartado la voluntad del causante para que otorgue testamento o deje de hacerlo, o lo modifique, así como los que falsifiquen, alteren, sustraigan, oculten o sustituyan el testamento; i) los que hayan incurrido en las demás causales de ingratitud que permiten revocar las donaciones. En todos los supuestos enunciados, basta la prueba de que al indigno le es imputable el hecho lesivo, sin necesidad de condena penal.", plainLanguageExplanation: "Establece el régimen de causas de indignidad. Son indignos de suceder: a) los autores, cómplices o partícipes de delito doloso contra la persona, el honor, la integridad sexual, la libertad o la propiedad del causante, o de sus descendientes, ascendientes, cónyuge, conviviente o hermanos.", practicalEffects: ['En la práctica, este artículo rige causas de indignidad. Son indignos de suceder: a) los autores, cómplices o partícipes de delito doloso contra la persona, el honor, la integridad sexual, la libertad o la p'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['causas', 'indignidad', 'articulo 2281'], segments: [], amendments: [] },
  { id: 'ccyc-art-2282', lawId: 'codigo-civil-comercial', number: '2282', order: 2282, title: "Perdón de la indignidad", text: "Perdón de la indignidad. El perdón del causante hace cesar la indignidad. El testamento en que se beneficia al indigno, posterior a los hechos de indignidad, comporta el perdón, excepto que se pruebe el desconocimiento de tales hechos por el testador.", plainLanguageExplanation: "Establece el régimen de perdón de la indignidad. El perdón del causante hace cesar la indignidad.", practicalEffects: ['En la práctica, este artículo rige perdón de la indignidad. El perdón del causante hace cesar la indignidad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['perdn', 'indignidad', 'articulo 2282'], segments: [], amendments: [] },
  { id: 'ccyc-art-2283', lawId: 'codigo-civil-comercial', number: '2283', order: 2283, title: "Ejercicio de la acción", text: "Ejercicio de la acción. La exclusión del indigno sólo puede ser demandada después de abierta la sucesión, a instancia de quien pretende los derechos atribuidos al indigno. También puede oponerla como excepción el demandado por reducción, colación o petición de herencia. La acción puede ser dirigida contra los sucesores a título gratuito del indigno y contra sus sucesores particulares a título oneroso de mala fe. Se considera de mala fe a quien conoce la existencia de la causa de indignidad.", plainLanguageExplanation: "Establece el régimen de ejercicio de la acción. La exclusión del indigno sólo puede ser demandada después de abierta la sucesión, a instancia de quien pretende los derechos atribuidos al indigno.", practicalEffects: ['En la práctica, este artículo rige ejercicio de la acción. La exclusión del indigno sólo puede ser demandada después de abierta la sucesión, a instancia de quien pretende los derechos atribuidos al indigno.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ejercicio', 'accin', 'articulo 2283'], segments: [], amendments: [] },
  { id: 'ccyc-art-2284', lawId: 'codigo-civil-comercial', number: '2284', order: 2284, title: "Caducidad", text: "Caducidad. Caduca el derecho de excluir al heredero indigno por el transcurso de tres años desde la apertura de la sucesión, y al legatario indigno por igual plazo desde la entrega del legado. Sin embargo, el demandado por el indigno por reducción, colación o petición de herencia, puede invocar la indignidad en todo tiempo.", plainLanguageExplanation: "Establece el régimen de caducidad. Caduca el derecho de excluir al heredero indigno por el transcurso de tres años desde la apertura de la sucesión, y al legatario indigno por igual plazo desde la entrega del legado.", practicalEffects: ['En la práctica, este artículo rige caducidad. Caduca el derecho de excluir al heredero indigno por el transcurso de tres años desde la apertura de la sucesión, y al legatario indigno por igual plazo desde la entrega del legado.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caducidadarticulo 2284'], segments: [], amendments: [] },
  { id: 'ccyc-art-2285', lawId: 'codigo-civil-comercial', number: '2285', order: 2285, title: "Efectos", text: "Efectos. Admitida judicialmente la exclusión, el indigno debe restituir los bienes recibidos, aplicándose lo dispuesto para el poseedor de mala fe. Debe también pagar intereses de las sumas de dinero recibidas, aunque no los haya percibido. Los derechos y obligaciones entre el indigno y el causante renacen, así como las garantías que los aseguraban. TITULO II Aceptación y renuncia de la herencia CAPITULO 1 Derecho de opción", plainLanguageExplanation: "Establece el régimen de efectos. Admitida judicialmente la exclusión, el indigno debe restituir los bienes recibidos, aplicándose lo dispuesto para el poseedor de mala fe.", practicalEffects: ['En la práctica, este artículo rige efectos. Admitida judicialmente la exclusión, el indigno debe restituir los bienes recibidos, aplicándose lo dispuesto para el poseedor de mala fe.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 2285'], segments: [], amendments: [] },
  { id: 'ccyc-art-2286', lawId: 'codigo-civil-comercial', number: '2286', order: 2286, title: "Tiempo de la aceptación y la renuncia", text: "Tiempo de la aceptación y la renuncia. Las herencias futuras no pueden ser aceptadas ni renunciadas.", plainLanguageExplanation: "Establece el régimen de tiempo de la aceptación y la renuncia. Las herencias futuras no pueden ser aceptadas ni renunciadas.", practicalEffects: ['En la práctica, este artículo rige tiempo de la aceptación y la renuncia. Las herencias futuras no pueden ser aceptadas ni renunciadas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['tiempo', 'aceptacin', 'renuncia', 'articulo 2286'], segments: [], amendments: [] },
  { id: 'ccyc-art-2287', lawId: 'codigo-civil-comercial', number: '2287', order: 2287, title: "Libertad de aceptar o renunciar", text: "Libertad de aceptar o renunciar. Todo heredero puede aceptar la herencia que le es deferida o renunciarla, pero no puede hacerlo por una parte de la herencia ni sujetar su opción a modalidades. La aceptación parcial implica la del todo; la aceptación bajo modalidades se tiene por no hecha.", plainLanguageExplanation: "Establece el régimen de libertad de aceptar o renunciar. Todo heredero puede aceptar la herencia que le es deferida o renunciarla, pero no puede hacerlo por una parte de la herencia ni sujetar su opción a modalidades.", practicalEffects: ['En la práctica, este artículo rige libertad de aceptar o renunciar. Todo heredero puede aceptar la herencia que le es deferida o renunciarla, pero no puede hacerlo por una parte de la herencia ni sujetar su opción a modalidades.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['libertad', 'aceptar', 'renunciar', 'articulo 2287'], segments: [], amendments: [] },
  { id: 'ccyc-art-2288', lawId: 'codigo-civil-comercial', number: '2288', order: 2288, title: "Caducidad del derecho de opción", text: "Caducidad del derecho de opción. El derecho de aceptar la herencia caduca a los diez años de la apertura de la sucesión. El heredero que no la haya aceptado en ese plazo es tenido por renunciante. El plazo para las personas llamadas a suceder en defecto de un heredero preferente que acepta la herencia y luego es excluido de ésta, corre a partir de la exclusión.", plainLanguageExplanation: "Establece el régimen de caducidad del derecho de opción. El derecho de aceptar la herencia caduca a los diez años de la apertura de la sucesión.", practicalEffects: ['En la práctica, este artículo rige caducidad del derecho de opción. El derecho de aceptar la herencia caduca a los diez años de la apertura de la sucesión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['caducidad', 'derecho', 'opcin', 'articulo 2288'], segments: [], amendments: [] },
  { id: 'ccyc-art-2289', lawId: 'codigo-civil-comercial', number: '2289', order: 2289, title: "Intimación a aceptar o renunciar", text: "Intimación a aceptar o renunciar. Cualquier interesado puede solicitar judicialmente que el heredero sea intimado a aceptar o renunciar la herencia en un plazo no menor de un mes ni mayor de tres meses, renovable una sola vez por justa causa. Transcurrido el plazo sin haber respondido la intimación, se lo tiene por aceptante. La intimación no puede ser hecha hasta pasados nueve días de la muerte del causante, sin perjuicio de que los interesados soliciten las medidas necesarias para resguardar sus derechos. Si el heredero ha sido instituido bajo condición suspensiva, la intimación sólo puede hacerse una vez cumplida la condición.", plainLanguageExplanation: "Establece el régimen de intimación a aceptar o renunciar. Cualquier interesado puede solicitar judicialmente que el heredero sea intimado a aceptar o renunciar la herencia en un plazo no menor de un mes ni mayor de tres meses, renovable una sola vez por justa causa.", practicalEffects: ['En la práctica, este artículo rige intimación a aceptar o renunciar. Cualquier interesado puede solicitar judicialmente que el heredero sea intimado a aceptar o renunciar la herencia en un plazo no menor de un mes ni ma'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['intimacin', 'aceptar', 'renunciar', 'articulo 2289'], segments: [], amendments: [] },
  { id: 'ccyc-art-2290', lawId: 'codigo-civil-comercial', number: '2290', order: 2290, title: "Transmisión del derecho de opción", text: "Transmisión del derecho de opción. Si el heredero fallece sin haber aceptado ni renunciado la herencia, el derecho de hacerlo se transmite a sus herederos. Si éstos no se ponen de acuerdo en aceptar o renunciar la herencia deferida a su causante, los que la aceptan adquieren la totalidad de los derechos y obligaciones que corresponden a éste. La renuncia de la herencia del causante fallecido sin aceptar ni renunciar una herencia a él deferida, implica también la renuncia a ésta.", plainLanguageExplanation: "Establece el régimen de transmisión del derecho de opción. Si el heredero fallece sin haber aceptado ni renunciado la herencia, el derecho de hacerlo se transmite a sus herederos.", practicalEffects: ['En la práctica, este artículo rige transmisión del derecho de opción. Si el heredero fallece sin haber aceptado ni renunciado la herencia, el derecho de hacerlo se transmite a sus herederos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['transmisin', 'derecho', 'opcin', 'articulo 2290'], segments: [], amendments: [] },
  { id: 'ccyc-art-2291', lawId: 'codigo-civil-comercial', number: '2291', order: 2291, title: "Efectos", text: "Efectos. El ejercicio del derecho de opción tiene efecto retroactivo al día de la apertura de la sucesión.", plainLanguageExplanation: "Establece el régimen de efectos. El ejercicio del derecho de opción tiene efecto retroactivo al día de la apertura de la sucesión.", practicalEffects: ['En la práctica, este artículo rige efectos. El ejercicio del derecho de opción tiene efecto retroactivo al día de la apertura de la sucesión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectosarticulo 2291'], segments: [], amendments: [] },
  { id: 'ccyc-art-2292', lawId: 'codigo-civil-comercial', number: '2292', order: 2292, title: "Acción de los acreedores del heredero", text: "Acción de los acreedores del heredero. Si el heredero renuncia a la herencia en perjuicio de sus acreedores, éstos pueden hacerse autorizar judicialmente para aceptarla en su nombre. En tal caso, la aceptación sólo tiene lugar a favor de los acreedores que la formulan y hasta la concurrencia del monto de sus créditos. CAPITULO 2 Aceptación de la herencia", plainLanguageExplanation: "Establece el régimen de acción de los acreedores del heredero. Si el heredero renuncia a la herencia en perjuicio de sus acreedores, éstos pueden hacerse autorizar judicialmente para aceptarla en su nombre.", practicalEffects: ['En la práctica, este artículo rige acción de los acreedores del heredero. Si el heredero renuncia a la herencia en perjuicio de sus acreedores, éstos pueden hacerse autorizar judicialmente para aceptarla en su nombre.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'acreedores', 'heredero', 'articulo 2292'], segments: [], amendments: [] },
  { id: 'ccyc-art-2293', lawId: 'codigo-civil-comercial', number: '2293', order: 2293, title: "Formas de aceptación", text: "Formas de aceptación. La aceptación de la herencia puede ser expresa o tácita. Es expresa cuando el heredero toma la calidad de tal en un acto otorgado por instrumento público o privado; es tácita si otorga un acto que supone necesariamente su intención de aceptar y que no puede haber realizado sino en calidad de heredero.", plainLanguageExplanation: "Establece el régimen de formas de aceptación. La aceptación de la herencia puede ser expresa o tácita.", practicalEffects: ['En la práctica, este artículo rige formas de aceptación. La aceptación de la herencia puede ser expresa o tácita.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formas', 'aceptacin', 'articulo 2293'], segments: [], amendments: [] },
  { id: 'ccyc-art-2294', lawId: 'codigo-civil-comercial', number: '2294', order: 2294, title: "Actos que implican aceptación", text: "Actos que implican aceptación. Implican aceptación de la herencia: a) la iniciación del juicio sucesorio del causante o la presentación en un juicio en el cual se pretende la calidad de heredero o derechos derivados de tal calidad; b) la disposición a título oneroso o gratuito de un bien o el ejercicio de actos posesorios sobre él; c) la ocupación o habitación de inmuebles de los que el causante era dueño o condómino después de transcurrido un año del deceso; d) el hecho de no oponer la falta de aceptación de la herencia en caso de haber sido demandado en calidad de heredero; e) la cesión de los derechos hereditarios, sea a título oneroso o gratuito; f) la renuncia de la herencia en favor de alguno o algunos de sus herederos, aunque sea gratuita; g) la renuncia de la herencia por un precio, aunque sea en favor de todos sus coherederos.", plainLanguageExplanation: "Establece el régimen de actos que implican aceptación. Implican aceptación de la herencia: a) la iniciación del juicio sucesorio del causante o la presentación en un juicio en el cual se pretende la calidad de heredero o derechos derivados de tal calidad; b) la disposición a título oneroso o gratuito de un bien o el ejercicio de acto", practicalEffects: ['En la práctica, este artículo rige actos que implican aceptación. Implican aceptación de la herencia: a) la iniciación del juicio sucesorio del causante o la presentación en un juicio en el cual se pretende la calida'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'implican', 'aceptacin', 'articulo 2294'], segments: [], amendments: [] },
  { id: 'ccyc-art-2295', lawId: 'codigo-civil-comercial', number: '2295', order: 2295, title: "Aceptación forzada", text: "Aceptación forzada. El heredero que oculta o sustrae bienes de la herencia es considerado aceptante con responsabilidad ilimitada, pierde el derecho de renunciar, y no tiene parte alguna en aquello que ha sido objeto de su ocultamiento o sustracción. En el supuesto de que no pueda restituir la cosa, debe restituir su valor, estimado al momento de la restitución.", plainLanguageExplanation: "Establece el régimen de aceptación forzada. El heredero que oculta o sustrae bienes de la herencia es considerado aceptante con responsabilidad ilimitada, pierde el derecho de renunciar, y no tiene parte alguna en aquello que ha sido objeto de su ocultamiento o sustracción.", practicalEffects: ['En la práctica, este artículo rige aceptación forzada. El heredero que oculta o sustrae bienes de la herencia es considerado aceptante con responsabilidad ilimitada, pierde el derecho de renunciar, y no ti'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aceptacin', 'forzada', 'articulo 2295'], segments: [], amendments: [] },
  { id: 'ccyc-art-2296', lawId: 'codigo-civil-comercial', number: '2296', order: 2296, title: "Actos que no implican aceptación", text: "Actos que no implican aceptación. No implican aceptación de la herencia: a) los actos puramente conservatorios, de supervisión o de administración provisional, así como los que resultan necesarios por circunstancias excepcionales y son ejecutados en interés de la sucesión; b) el pago de los gastos funerarios y de la última enfermedad, los impuestos adeudados por el difunto, los alquileres y otras deudas cuyo pago es urgente; c) el reparto de ropas, documentos personales, condecoraciones y diplomas del difunto, o recuerdos de familia, hecho con el acuerdo de todos los herederos; d) el cobro de las rentas de los bienes de la herencia, si se emplean en los pagos a que se refiere el inciso b) o se depositan en poder de un escribano; e) la venta de bienes perecederos efectuada antes de la designación del administrador, si se da al precio el destino dispuesto en el inciso d) de este artículo; en caso de no poderse hallar comprador en tiempo útil, su donación a entidades de asistencia social o su reparto entre todos los herederos; f) la venta de bienes cuya conservación es dispendiosa o son susceptibles de desvalorizarse rápidamente, si se da al precio el destino dispuesto en el inciso d). En los tres últimos casos, el que ha percibido las rentas o el precio de las ventas queda sujeto a las obligaciones y responsabilidad del administrador de bienes ajenos.", plainLanguageExplanation: "Establece el régimen de actos que no implican aceptación. No implican aceptación de la herencia: a) los actos puramente conservatorios, de supervisión o de administración provisional, así como los que resultan necesarios por circunstancias excepcionales y son ejecutados en interés de la sucesión; b) el pago de los gastos funerarios y de", practicalEffects: ['En la práctica, este artículo rige actos que no implican aceptación. No implican aceptación de la herencia: a) los actos puramente conservatorios, de supervisión o de administración provisional, así como los que resulta'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'implican', 'aceptacin', 'articulo 2296'], segments: [], amendments: [] },
  { id: 'ccyc-art-2297', lawId: 'codigo-civil-comercial', number: '2297', order: 2297, title: "Aceptación por una persona incapaz o con capacidad restringida", text: "Aceptación por una persona incapaz o con capacidad restringida. La aceptación de la herencia por el representante legal de una persona incapaz nunca puede obligar a éste al pago de las deudas de la sucesión más allá del valor de los bienes que le sean atribuidos. Igual regla se aplica a la aceptación de la herencia por una persona con capacidad restringida, aunque haya actuado con asistencia, o por su representante legal o convencional. CAPITULO 3 Renuncia de la herencia", plainLanguageExplanation: "Establece el régimen de aceptación por una persona incapaz o con capacidad restringida. La aceptación de la herencia por el representante legal de una persona incapaz nunca puede obligar a éste al pago de las deudas de la sucesión más allá del valor de los bienes que le sean atribuidos.", practicalEffects: ['En la práctica, este artículo rige aceptación por una persona incapaz o con capacidad restringida. La aceptación de la herencia por el representante legal de una persona incapaz nunca puede obligar a éste al pago de las deudas de la sucesión más allá del valor de los bienes que le sean atribuidos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aceptacin', 'persona', 'incapaz', 'capacidad', 'restringida', 'articulo 2297'], segments: [], amendments: [] },
  { id: 'ccyc-art-2298', lawId: 'codigo-civil-comercial', number: '2298', order: 2298, title: "Facultad de renunciar", text: "Facultad de renunciar. El heredero puede renunciar a la herencia en tanto no haya mediado acto de aceptación.", plainLanguageExplanation: "Establece el régimen de facultad de renunciar. El heredero puede renunciar a la herencia en tanto no haya mediado acto de aceptación.", practicalEffects: ['En la práctica, este artículo rige facultad de renunciar. El heredero puede renunciar a la herencia en tanto no haya mediado acto de aceptación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultad', 'renunciar', 'articulo 2298'], segments: [], amendments: [] },
  { id: 'ccyc-art-2299', lawId: 'codigo-civil-comercial', number: '2299', order: 2299, title: "Forma de la renuncia", text: "Forma de la renuncia. La renuncia de la herencia debe ser expresada en escritura pública; también puede ser hecha en acta judicial incorporada al expediente judicial, siempre que el sistema informático asegure la inalterabilidad del instrumento.", plainLanguageExplanation: "Establece el régimen de forma de la renuncia. La renuncia de la herencia debe ser expresada en escritura pública; también puede ser hecha en acta judicial incorporada al expediente judicial, siempre que el sistema informático asegure la inalterabilidad del instrumento.", practicalEffects: ['En la práctica, este artículo rige forma de la renuncia. La renuncia de la herencia debe ser expresada en escritura pública; también puede ser hecha en acta judicial incorporada al expediente judicial, siemp'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['forma', 'renuncia', 'articulo 2299'], segments: [], amendments: [] },
  { id: 'ccyc-art-2300', lawId: 'codigo-civil-comercial', number: '2300', order: 2300, title: "Retractación de la renuncia", text: "Retractación de la renuncia. El heredero renunciante puede retractar su renuncia en tanto no haya caducado su derecho de opción, si la herencia no ha sido aceptada por otros herederos ni se ha puesto al Estado en posesión de los bienes. La retractación no afecta los derechos adquiridos por terceros sobre los bienes de la herencia.", plainLanguageExplanation: "Establece el régimen de retractación de la renuncia. El heredero renunciante puede retractar su renuncia en tanto no haya caducado su derecho de opción, si la herencia no ha sido aceptada por otros herederos ni se ha puesto al Estado en posesión de los bienes.", practicalEffects: ['En la práctica, este artículo rige retractación de la renuncia. El heredero renunciante puede retractar su renuncia en tanto no haya caducado su derecho de opción, si la herencia no ha sido aceptada por otros hered'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['retractacin', 'renuncia', 'articulo 2300'], segments: [], amendments: [] },
  { id: 'ccyc-art-2301', lawId: 'codigo-civil-comercial', number: '2301', order: 2301, title: "Efectos de la renuncia", text: "Efectos de la renuncia. El heredero renunciante es considerado como si nunca hubiese sido llamado a la herencia, sin perjuicio de la apertura del derecho de representación en los casos en que por este Código tiene lugar. TITULO III Cesión de herencia", plainLanguageExplanation: "Establece el régimen de efectos de la renuncia. El heredero renunciante es considerado como si nunca hubiese sido llamado a la herencia, sin perjuicio de la apertura del derecho de representación en los casos en que por este Código tiene lugar.", practicalEffects: ['En la práctica, este artículo rige efectos de la renuncia. El heredero renunciante es considerado como si nunca hubiese sido llamado a la herencia, sin perjuicio de la apertura del derecho de representación en los casos en que por este Código tiene lugar.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'renuncia', 'articulo 2301'], segments: [], amendments: [] },
  { id: 'ccyc-art-2302', lawId: 'codigo-civil-comercial', number: '2302', order: 2302, title: "Momento a partir del cual produce efectos", text: "Momento a partir del cual produce efectos. La cesión del derecho a una herencia ya deferida o a una parte indivisa de ella tiene efectos: a) entre los contratantes, desde su celebración; b) respecto de otros herederos, legatarios y acreedores del cedente, desde que la escritura pública se incorpora al expediente sucesorio; c) respecto al deudor de un crédito de la herencia, desde que se le notifica la cesión.", plainLanguageExplanation: "Establece el régimen de momento a partir del cual produce efectos. La cesión del derecho a una herencia ya deferida o a una parte indivisa de ella tiene efectos: a) entre los contratantes, desde su celebración; b) respecto de otros herederos, legatarios y acreedores del cedente, desde que la escritura pública se incorpora al expediente sucesorio", practicalEffects: ['En la práctica, este artículo rige momento a partir del cual produce efectos. La cesión del derecho a una herencia ya deferida o a una parte indivisa de ella tiene efectos: a) entre los contratantes, desde su celebración; b) res'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['momento', 'partir', 'cual', 'produce', 'efectos', 'articulo 2302'], segments: [], amendments: [] },
  { id: 'ccyc-art-2303', lawId: 'codigo-civil-comercial', number: '2303', order: 2303, title: "Extensión y exclusiones", text: "Extensión y exclusiones. La cesión de herencia comprende las ventajas que pueden resultar ulteriormente por colación, por la renuncia a disposiciones particulares del testamento, o por la caducidad de éstas. No comprende, excepto pacto en contrario: a) lo acrecido con posterioridad en razón de una causa diversa de las expresadas, como la renuncia o la exclusión de un coheredero; b) lo acrecido anteriormente por una causa desconocida al tiempo de la cesión; c) los derechos sobre los sepulcros, los documentos privados del causante, distinciones honoríficas, retratos y recuerdos de familia.", plainLanguageExplanation: "Establece el régimen de extensión y exclusiones. La cesión de herencia comprende las ventajas que pueden resultar ulteriormente por colación, por la renuncia a disposiciones particulares del testamento, o por la caducidad de éstas.", practicalEffects: ['En la práctica, este artículo rige extensión y exclusiones. La cesión de herencia comprende las ventajas que pueden resultar ulteriormente por colación, por la renuncia a disposiciones particulares del testamento, o por la caducidad de éstas.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extensin', 'exclusiones', 'articulo 2303'], segments: [], amendments: [] },
  { id: 'ccyc-art-2304', lawId: 'codigo-civil-comercial', number: '2304', order: 2304, title: "Derechos del cesionario", text: "Derechos del cesionario. El cesionario adquiere los mismos derechos que le correspondían al cedente en la herencia. Asimismo, tiene derecho de participar en el valor íntegro de los bienes que se gravaron después de la apertura de la sucesión y antes de la cesión, y en el de los que en el mismo período se consumieron o enajenaron, con excepción de los frutos percibidos.", plainLanguageExplanation: "Establece el régimen de derechos del cesionario. El cesionario adquiere los mismos derechos que le correspondían al cedente en la herencia.", practicalEffects: ['En la práctica, este artículo rige derechos del cesionario. El cesionario adquiere los mismos derechos que le correspondían al cedente en la herencia.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'cesionario', 'articulo 2304'], segments: [], amendments: [] },
  { id: 'ccyc-art-2305', lawId: 'codigo-civil-comercial', number: '2305', order: 2305, title: "Garantía por evicción", text: "Garantía por evicción. Si la cesión es onerosa, el cedente garantiza al cesionario su calidad de heredero y la parte indivisa que le corresponde en la herencia, excepto que sus derechos hayan sido cedidos como litigiosos o dudosos, sin dolo de su parte. No responde por la evicción ni por los vicios de los bienes de la herencia, excepto pacto en contrario. En lo demás, su responsabilidad se rige por las normas relativas a la cesión de derechos. Si la cesión es gratuita, el cedente sólo responde en los casos en que el donante es responsable. Su responsabilidad se limita al daño causado de mala fe.", plainLanguageExplanation: "Establece el régimen de garantía por evicción. Si la cesión es onerosa, el cedente garantiza al cesionario su calidad de heredero y la parte indivisa que le corresponde en la herencia, excepto que sus derechos hayan sido cedidos como litigiosos o dudosos, sin dolo de su parte.", practicalEffects: ['En la práctica, este artículo rige garantía por evicción. Si la cesión es onerosa, el cedente garantiza al cesionario su calidad de heredero y la parte indivisa que le corresponde en la herencia, excepto que'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garanta', 'eviccin', 'articulo 2305'], segments: [], amendments: [] },
  { id: 'ccyc-art-2306', lawId: 'codigo-civil-comercial', number: '2306', order: 2306, title: "Efectos sobre la confusión", text: "Efectos sobre la confusión. La cesión no produce efecto alguno sobre la extinción de las obligaciones causada por confusión.", plainLanguageExplanation: "Establece el régimen de efectos sobre la confusión. La cesión no produce efecto alguno sobre la extinción de las obligaciones causada por confusión.", practicalEffects: ['En la práctica, este artículo rige efectos sobre la confusión. La cesión no produce efecto alguno sobre la extinción de las obligaciones causada por confusión.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efectos', 'sobre', 'confusin', 'articulo 2306'], segments: [], amendments: [] },
  { id: 'ccyc-art-2307', lawId: 'codigo-civil-comercial', number: '2307', order: 2307, title: "Obligaciones del cesionario", text: "Obligaciones del cesionario. El cesionario debe reembolsar al cedente lo que éste pague por su parte en las deudas y cargas de la sucesión hasta la concurrencia del valor de la porción de la herencia recibida. Las cargas particulares del cedente y los tributos que gravan la transmisión hereditaria están a cargo del cesionario si están impagos al tiempo de la cesión.", plainLanguageExplanation: "Establece el régimen de obligaciones del cesionario. El cesionario debe reembolsar al cedente lo que éste pague por su parte en las deudas y cargas de la sucesión hasta la concurrencia del valor de la porción de la herencia recibida.", practicalEffects: ['En la práctica, este artículo rige obligaciones del cesionario. El cesionario debe reembolsar al cedente lo que éste pague por su parte en las deudas y cargas de la sucesión hasta la concurrencia del valor de la porción de la herencia recibida.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['obligaciones', 'cesionario', 'articulo 2307'], segments: [], amendments: [] },
  { id: 'ccyc-art-2308', lawId: 'codigo-civil-comercial', number: '2308', order: 2308, title: "Indivisión postcomunitaria", text: "Indivisión postcomunitaria. Las disposiciones de este título se aplican a la cesión de los derechos que corresponden a un cónyuge en la indivisión postcomunitaria que acaece por muerte del otro cónyuge.", plainLanguageExplanation: "Establece el régimen de indivisión postcomunitaria. Las disposiciones de este título se aplican a la cesión de los derechos que corresponden a un cónyuge en la indivisión postcomunitaria que acaece por muerte del otro cónyuge.", practicalEffects: ['En la práctica, este artículo rige indivisión postcomunitaria. Las disposiciones de este título se aplican a la cesión de los derechos que corresponden a un cónyuge en la indivisión postcomunitaria que acaece por'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indivisin', 'postcomunitaria', 'articulo 2308'], segments: [], amendments: [] },
  { id: 'ccyc-art-2309', lawId: 'codigo-civil-comercial', number: '2309', order: 2309, title: "Cesión de bienes determinados", text: "Cesión de bienes determinados. La cesión de derechos sobre bienes determinados que forman parte de una herencia no se rige por las reglas de este Título, sino por las del contrato que corresponde, y su eficacia está sujeta a que el bien sea atribuido al cedente en la partición. TITULO IV Petición de herencia", plainLanguageExplanation: "Establece el régimen de cesión de bienes determinados. La cesión de derechos sobre bienes determinados que forman parte de una herencia no se rige por las reglas de este Título, sino por las del contrato que corresponde, y su eficacia está sujeta a que el bien sea atribuido al cedente en la partición.", practicalEffects: ['En la práctica, este artículo rige cesión de bienes determinados. La cesión de derechos sobre bienes determinados que forman parte de una herencia no se rige por las reglas de este Título, sino por las del contrato q'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cesin', 'bienes', 'determinados', 'articulo 2309'], segments: [], amendments: [] },
  { id: 'ccyc-art-2310', lawId: 'codigo-civil-comercial', number: '2310', order: 2310, title: "Procedencia", text: "Procedencia. La petición de herencia procede para obtener la entrega total o parcial de la herencia, sobre la base del reconocimiento de la calidad del heredero del actor, contra el que está en posesión material de la herencia, e invoca el título de heredero.", plainLanguageExplanation: "Establece el régimen de procedencia. La petición de herencia procede para obtener la entrega total o parcial de la herencia, sobre la base del reconocimiento de la calidad del heredero del actor, contra el que está en posesión material de la herencia, e invoca el título de heredero.", practicalEffects: ['En la práctica, este artículo rige procedencia. La petición de herencia procede para obtener la entrega total o parcial de la herencia, sobre la base del reconocimiento de la calidad del heredero de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procedenciaarticulo 2310'], segments: [], amendments: [] },
  { id: 'ccyc-art-2311', lawId: 'codigo-civil-comercial', number: '2311', order: 2311, title: "Imprescriptibilidad", text: "Imprescriptibilidad. La petición de herencia es imprescriptible, sin perjuicio de la prescripción adquisitiva que puede operar con relación a cosas singulares.", plainLanguageExplanation: "Establece el régimen de imprescriptibilidad. La petición de herencia es imprescriptible, sin perjuicio de la prescripción adquisitiva que puede operar con relación a cosas singulares.", practicalEffects: ['En la práctica, este artículo rige imprescriptibilidad. La petición de herencia es imprescriptible, sin perjuicio de la prescripción adquisitiva que puede operar con relación a cosas singulares.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['imprescriptibilidadarticulo 2311'], segments: [], amendments: [] },
  { id: 'ccyc-art-2312', lawId: 'codigo-civil-comercial', number: '2312', order: 2312, title: "Restitución de los bienes", text: "Restitución de los bienes. Admitida la petición de herencia, el heredero aparente debe restituir lo que recibió sin derecho en la sucesión, inclusive las cosas de las que el causante era poseedor y aquellas sobre las cuales ejercía el derecho de retención. Si no es posible la restitución en especie, debe indemnización de los daños. El cesionario de los derechos hereditarios del heredero aparente está equiparado a éste en las relaciones con el demandante.", plainLanguageExplanation: "Establece el régimen de restitución de los bienes. Admitida la petición de herencia, el heredero aparente debe restituir lo que recibió sin derecho en la sucesión, inclusive las cosas de las que el causante era poseedor y aquellas sobre las cuales ejercía el derecho de retención.", practicalEffects: ['En la práctica, este artículo rige restitución de los bienes. Admitida la petición de herencia, el heredero aparente debe restituir lo que recibió sin derecho en la sucesión, inclusive las cosas de las que el cau'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['restitucin', 'bienes', 'articulo 2312'], segments: [], amendments: [] },
  { id: 'ccyc-art-2313', lawId: 'codigo-civil-comercial', number: '2313', order: 2313, title: "Reglas aplicables", text: "Reglas aplicables. Se aplica a la petición de herencia lo dispuesto sobre la reivindicación en cuanto a las obligaciones del poseedor de buena o mala fe, gastos, mejoras, apropiación de frutos y productos, responsabilidad por pérdidas y deterioros. Es poseedor de mala fe el que conoce o debió conocer la existencia de herederos preferentes o concurrentes que ignoraban su llamamiento.", plainLanguageExplanation: "Establece el régimen de reglas aplicables. Se aplica a la petición de herencia lo dispuesto sobre la reivindicación en cuanto a las obligaciones del poseedor de buena o mala fe, gastos, mejoras, apropiación de frutos y productos, responsabilidad por pérdidas y deterioros.", practicalEffects: ['En la práctica, este artículo rige reglas aplicables. Se aplica a la petición de herencia lo dispuesto sobre la reivindicación en cuanto a las obligaciones del poseedor de buena o mala fe, gastos, mejoras'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reglas', 'aplicables', 'articulo 2313'], segments: [], amendments: [] },
  { id: 'ccyc-art-2314', lawId: 'codigo-civil-comercial', number: '2314', order: 2314, title: "Derechos del heredero aparente", text: "Derechos del heredero aparente. Si el heredero aparente satisface obligaciones del causante con bienes no provenientes de la herencia, tiene derecho a ser reembolsado por el heredero.", plainLanguageExplanation: "Establece el régimen de derechos del heredero aparente. Si el heredero aparente satisface obligaciones del causante con bienes no provenientes de la herencia, tiene derecho a ser reembolsado por el heredero.", practicalEffects: ['En la práctica, este artículo rige derechos del heredero aparente. Si el heredero aparente satisface obligaciones del causante con bienes no provenientes de la herencia, tiene derecho a ser reembolsado por el heredero'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'heredero', 'aparente', 'articulo 2314'], segments: [], amendments: [] },
  { id: 'ccyc-art-2315', lawId: 'codigo-civil-comercial', number: '2315', order: 2315, title: "Actos del heredero aparente", text: "Actos del heredero aparente. Son válidos los actos de administración del heredero aparente realizados hasta la notificación de la demanda de petición de herencia, excepto que haya habido mala fe suya y del tercero con quien contrató. Son también válidos los actos de disposición a título oneroso en favor de terceros que ignoran la existencia de herederos de mejor o igual derecho que el heredero aparente, o que los derechos de éste están judicialmente controvertidos. El heredero aparente de buena fe debe restituir al heredero el precio recibido; el de mala fe debe indemnizar todo perjuicio que le haya causado. TITULO V Responsabilidad de los herederos y legatarios. Liquidación del pasivo", plainLanguageExplanation: "Establece el régimen de actos del heredero aparente. Son válidos los actos de administración del heredero aparente realizados hasta la notificación de la demanda de petición de herencia, excepto que haya habido mala fe suya y del tercero con quien contrató.", practicalEffects: ['En la práctica, este artículo rige actos del heredero aparente. Son válidos los actos de administración del heredero aparente realizados hasta la notificación de la demanda de petición de herencia, excepto que haya'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'heredero', 'aparente', 'articulo 2315'], segments: [], amendments: [] },
  { id: 'ccyc-art-2316', lawId: 'codigo-civil-comercial', number: '2316', order: 2316, title: "Preferencia", text: "Preferencia. Los acreedores por deudas del causante y por cargas de la sucesión, y los legatarios tienen derecho al cobro de sus créditos y legados sobre los bienes de la herencia, con preferencia sobre los acreedores de los herederos.", plainLanguageExplanation: "Establece el régimen de preferencia. Los acreedores por deudas del causante y por cargas de la sucesión, y los legatarios tienen derecho al cobro de sus créditos y legados sobre los bienes de la herencia, con preferencia sobre los acreedores de los herederos.", practicalEffects: ['En la práctica, este artículo rige preferencia. Los acreedores por deudas del causante y por cargas de la sucesión, y los legatarios tienen derecho al cobro de sus créditos y legados sobre los biene'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['preferenciaarticulo 2316'], segments: [], amendments: [] },
  { id: 'ccyc-art-2317', lawId: 'codigo-civil-comercial', number: '2317', order: 2317, title: "Responsabilidad del heredero", text: "Responsabilidad del heredero. El heredero queda obligado por las deudas y legados de la sucesión sólo hasta la concurrencia del valor de los bienes hereditarios recibidos. En caso de pluralidad de herederos, éstos responden con la masa hereditaria indivisa.", plainLanguageExplanation: "Establece el régimen de responsabilidad del heredero. El heredero queda obligado por las deudas y legados de la sucesión sólo hasta la concurrencia del valor de los bienes hereditarios recibidos.", practicalEffects: ['En la práctica, este artículo rige responsabilidad del heredero. El heredero queda obligado por las deudas y legados de la sucesión sólo hasta la concurrencia del valor de los bienes hereditarios recibidos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'heredero', 'articulo 2317'], segments: [], amendments: [] },
  { id: 'ccyc-art-2318', lawId: 'codigo-civil-comercial', number: '2318', order: 2318, title: "Legado de universalidad", text: "Legado de universalidad. Si el legado es de una universalidad de bienes y deudas, el legatario sólo queda obligado al pago de las deudas comprendidas en aquélla hasta el valor de los bienes recibidos, sin perjuicio de la acción subsidiaria de los acreedores contra los herederos y los otros legatarios en caso de insuficiencia de los bienes de la universalidad.", plainLanguageExplanation: "Establece el régimen de legado de universalidad. Si el legado es de una universalidad de bienes y deudas, el legatario sólo queda obligado al pago de las deudas comprendidas en aquélla hasta el valor de los bienes recibidos, sin perjuicio de la acción subsidiaria de los acreedores contra los herederos y los otros legatarios en", practicalEffects: ['En la práctica, este artículo rige legado de universalidad. Si el legado es de una universalidad de bienes y deudas, el legatario sólo queda obligado al pago de las deudas comprendidas en aquélla hasta el valor'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legado', 'universalidad', 'articulo 2318'], segments: [], amendments: [] },
  { id: 'ccyc-art-2319', lawId: 'codigo-civil-comercial', number: '2319', order: 2319, title: "Acción contra los legatarios", text: "Acción contra los legatarios. Los acreedores del causante tienen acción contra los legatarios hasta el valor de lo que reciben; esta acción caduca al año contado desde el día en que cobran sus legados.", plainLanguageExplanation: "Establece el régimen de acción contra los legatarios. Los acreedores del causante tienen acción contra los legatarios hasta el valor de lo que reciben; esta acción caduca al año contado desde el día en que cobran sus legados.", practicalEffects: ['En la práctica, este artículo rige acción contra los legatarios. Los acreedores del causante tienen acción contra los legatarios hasta el valor de lo que reciben; esta acción caduca al año contado desde el día en qu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'contra', 'legatarios', 'articulo 2319'], segments: [], amendments: [] },
  { id: 'ccyc-art-2320', lawId: 'codigo-civil-comercial', number: '2320', order: 2320, title: "Reembolso", text: "Reembolso. El heredero o legatario que paga una porción de las deudas o de los legados superior a su parte tiene acción contra sus coherederos o colegatarios por el reembolso del excedente, y hasta el límite de la parte que cada uno de ellos debía soportar personalmente, incluso en caso de subrogación en los derechos del que recibe el pago.", plainLanguageExplanation: "Establece el régimen de reembolso. El heredero o legatario que paga una porción de las deudas o de los legados superior a su parte tiene acción contra sus coherederos o colegatarios por el reembolso del excedente, y hasta el límite de la parte que cada uno de ellos debía soportar personalmente, incluso en caso de", practicalEffects: ['En la práctica, este artículo rige reembolso. El heredero o legatario que paga una porción de las deudas o de los legados superior a su parte tiene acción contra sus coherederos o colegatarios por'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['reembolsoarticulo 2320'], segments: [], amendments: [] },
  { id: 'ccyc-art-2321', lawId: 'codigo-civil-comercial', number: '2321', order: 2321, title: "Responsabilidad con los propios bienes", text: "Responsabilidad con los propios bienes. Responde con sus propios bienes por el pago de las deudas del causante y cargas de la herencia, el heredero que: a) no hace el inventario en el plazo de tres meses desde que los acreedores o legatarios lo intiman judicialmente a su realización; b) oculta fraudulentamente los bienes de la sucesión omitiendo su inclusión en el inventario; c) exagera dolosamente el pasivo sucesorio; d) enajena bienes de la sucesión, excepto que el acto sea conveniente y el precio obtenido ingrese a la masa.", plainLanguageExplanation: "Establece el régimen de responsabilidad con los propios bienes. Responde con sus propios bienes por el pago de las deudas del causante y cargas de la herencia, el heredero que: a) no hace el inventario en el plazo de tres meses desde que los acreedores o legatarios lo intiman judicialmente a su realización; b) oculta fraudulentamente los bien", practicalEffects: ['En la práctica, este artículo rige responsabilidad con los propios bienes. Responde con sus propios bienes por el pago de las deudas del causante y cargas de la herencia, el heredero que: a) no hace el inventario en el plazo'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['responsabilidad', 'propios', 'bienes', 'articulo 2321'], segments: [], amendments: [] },
  { id: 'ccyc-art-2322', lawId: 'codigo-civil-comercial', number: '2322', order: 2322, title: "Prioridad de los acreedores del heredero sobre los bienes del heredero", text: "Prioridad de los acreedores del heredero sobre los bienes del heredero. En los casos previstos en el artículo 2321, sobre los bienes del heredero, los acreedores del heredero cobran según el siguiente rango: a) por los créditos originados antes de la apertura de la sucesión, con preferencia respecto de los acreedores del causante y de los legatarios; b) por créditos originados después de la apertura de la sucesión concurren a prorrata con los acreedores del causante. TITULO VI Estado de indivisión CAPITULO 1 Administración extrajudicial", plainLanguageExplanation: "Establece el régimen de prioridad de los acreedores del heredero sobre los bienes del heredero. En los casos previstos en el artículo 2321, sobre los bienes del heredero, los acreedores del heredero cobran según el siguiente rango: a) por los créditos originados antes de la apertura de la sucesión, con preferencia respecto de los acreedores del causante y de los legatarios;", practicalEffects: ['En la práctica, este artículo rige prioridad de los acreedores del heredero sobre los bienes del heredero. En los casos previstos en el artículo 2321, sobre los bienes del heredero, los acreedores del heredero cobran según el siguiente rango: a) por los cré'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prioridad', 'acreedores', 'heredero', 'sobre', 'bienes', 'articulo 2322'], segments: [], amendments: [] },
  { id: 'ccyc-art-2323', lawId: 'codigo-civil-comercial', number: '2323', order: 2323, title: "Aplicabilidad", text: "Aplicabilidad. Las disposiciones de este Título se aplican en toda sucesión en la que hay más de un heredero, desde la muerte del causante hasta la partición, si no hay administrador designado.", plainLanguageExplanation: "Establece el régimen de aplicabilidad. Las disposiciones de este Título se aplican en toda sucesión en la que hay más de un heredero, desde la muerte del causante hasta la partición, si no hay administrador designado.", practicalEffects: ['En la práctica, este artículo rige aplicabilidad. Las disposiciones de este Título se aplican en toda sucesión en la que hay más de un heredero, desde la muerte del causante hasta la partición, si no'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['aplicabilidadarticulo 2323'], segments: [], amendments: [] },
  { id: 'ccyc-art-2324', lawId: 'codigo-civil-comercial', number: '2324', order: 2324, title: "Actos conservatorios y medidas urgentes", text: "Actos conservatorios y medidas urgentes. Cualquiera de los herederos puede tomar las medidas necesarias para la conservación de los bienes indivisos, empleando a tal fin los fondos indivisos que se encuentran en su poder. A falta de ellos, puede obligar a los coherederos a contribuir al pago de los gastos necesarios.", plainLanguageExplanation: "Establece el régimen de actos conservatorios y medidas urgentes. Cualquiera de los herederos puede tomar las medidas necesarias para la conservación de los bienes indivisos, empleando a tal fin los fondos indivisos que se encuentran en su poder.", practicalEffects: ['En la práctica, este artículo rige actos conservatorios y medidas urgentes. Cualquiera de los herederos puede tomar las medidas necesarias para la conservación de los bienes indivisos, empleando a tal fin los fondos indivisos que se encuentran en su poder.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'conservatorios', 'medidas', 'urgentes', 'articulo 2324'], segments: [], amendments: [] },
  { id: 'ccyc-art-2325', lawId: 'codigo-civil-comercial', number: '2325', order: 2325, title: "Actos de administración y de disposición", text: "Actos de administración y de disposición. Los actos de administración y de disposición requieren el consentimiento de todos los coherederos, quienes pueden dar a uno o varios de ellos o a terceros un mandato general de administración. Son necesarias facultades expresas para todo acto que excede la explotación normal de los bienes indivisos y para la contratación y renovación de locaciones. Si uno de los coherederos toma a su cargo la administración con conocimiento de los otros y sin oposición de ellos, se considera que hay un mandato tácito para los actos de administración que no requieren facultades expresas en los términos del párrafo anterior.", plainLanguageExplanation: "Establece el régimen de actos de administración y de disposición. Los actos de administración y de disposición requieren el consentimiento de todos los coherederos, quienes pueden dar a uno o varios de ellos o a terceros un mandato general de administración.", practicalEffects: ['En la práctica, este artículo rige actos de administración y de disposición. Los actos de administración y de disposición requieren el consentimiento de todos los coherederos, quienes pueden dar a uno o varios de ellos o a terceros un mandato general de administración.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['actos', 'administracin', 'disposicin', 'articulo 2325'], segments: [], amendments: [] },
  { id: 'ccyc-art-2326', lawId: 'codigo-civil-comercial', number: '2326', order: 2326, title: "Ausencia o impedimento", text: "Ausencia o impedimento. Los actos otorgados por un coheredero en representación de otro que está ausente, o impedido transitoriamente, se rigen por las normas de la gestión de negocios.", plainLanguageExplanation: "Establece el régimen de ausencia o impedimento. Los actos otorgados por un coheredero en representación de otro que está ausente, o impedido transitoriamente, se rigen por las normas de la gestión de negocios.", practicalEffects: ['En la práctica, este artículo rige ausencia o impedimento. Los actos otorgados por un coheredero en representación de otro que está ausente, o impedido transitoriamente, se rigen por las normas de la gestión d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ausencia', 'impedimento', 'articulo 2326'], segments: [], amendments: [] },
  { id: 'ccyc-art-2327', lawId: 'codigo-civil-comercial', number: '2327', order: 2327, title: "Medidas urgentes", text: "Medidas urgentes. Aun antes de la apertura del proceso judicial sucesorio, a pedido de un coheredero, el juez puede ordenar todas las medidas urgentes que requiere el interés común, entre ellas, autorizar el ejercicio de derechos derivados de títulos valores, acciones o cuotas societarias, la percepción de fondos indivisos, o el otorgamiento de actos para los cuales es necesario el consentimiento de los demás sucesores, si la negativa de éstos pone en peligro el interés común. Asimismo, puede designar un administrador provisorio, prohibir el desplazamiento de cosas muebles, y atribuir a uno u otro de los coherederos el uso personal de éstas.", plainLanguageExplanation: "Establece el régimen de medidas urgentes. Aun antes de la apertura del proceso judicial sucesorio, a pedido de un coheredero, el juez puede ordenar todas las medidas urgentes que requiere el interés común, entre ellas, autorizar el ejercicio de derechos derivados de títulos valores, acciones o cuotas societarias, la perc", practicalEffects: ['En la práctica, este artículo rige medidas urgentes. Aun antes de la apertura del proceso judicial sucesorio, a pedido de un coheredero, el juez puede ordenar todas las medidas urgentes que requiere el i'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medidas', 'urgentes', 'articulo 2327'], segments: [], amendments: [] },
  { id: 'ccyc-art-2328', lawId: 'codigo-civil-comercial', number: '2328', order: 2328, title: "Uso y goce de los bienes", text: "Uso y goce de los bienes. El heredero puede usar y disfrutar de la cosa indivisa conforme a su destino, en la medida compatible con el derecho de los otros copartícipes. Si no hay acuerdo entre los interesados, el ejercicio de este derecho debe ser regulado, de manera provisional, por el juez. El copartícipe que usa privativamente de la cosa indivisa está obligado, excepto pacto en contrario, a satisfacer una indemnización, desde que le es requerida.", plainLanguageExplanation: "Establece el régimen de uso y goce de los bienes. El heredero puede usar y disfrutar de la cosa indivisa conforme a su destino, en la medida compatible con el derecho de los otros copartícipes.", practicalEffects: ['En la práctica, este artículo rige uso y goce de los bienes. El heredero puede usar y disfrutar de la cosa indivisa conforme a su destino, en la medida compatible con el derecho de los otros copartícipes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['goce', 'bienes', 'articulo 2328'], segments: [], amendments: [] },
  { id: 'ccyc-art-2329', lawId: 'codigo-civil-comercial', number: '2329', order: 2329, title: "Frutos", text: "Frutos. Los frutos de los bienes indivisos acrecen a la indivisión, excepto que medie partición provisional. Cada uno de los herederos tiene derecho a los beneficios y soporta las pérdidas proporcionalmente a su parte en la indivisión. CAPITULO 2 Indivisión forzosa", plainLanguageExplanation: "Establece el régimen de frutos. Los frutos de los bienes indivisos acrecen a la indivisión, excepto que medie partición provisional.", practicalEffects: ['En la práctica, este artículo rige frutos. Los frutos de los bienes indivisos acrecen a la indivisión, excepto que medie partición provisional.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['frutosarticulo 2329'], segments: [], amendments: [] },
  { id: 'ccyc-art-2330', lawId: 'codigo-civil-comercial', number: '2330', order: 2330, title: "Indivisión impuesta por el testador", text: "Indivisión impuesta por el testador. El testador puede imponer a sus herederos, aun legitimarios, la indivisión de la herencia por un plazo no mayor de diez años. Puede también disponer que se mantenga indiviso por ese plazo o, en caso de haber herederos menores de edad, hasta que todos ellos lleguen a la mayoría de edad: a) un bien determinado; b) un establecimiento comercial, industrial, agrícola, ganadero, minero, o cualquier otro que constituye una unidad económica; c) las partes sociales, cuotas o acciones de la sociedad de la cual es principal socio o accionista. En todos los casos, cualquier plazo superior al máximo permitido se entiende reducido a éste. El juez puede autorizar la división total o parcial antes de vencer el plazo, a pedido de un coheredero, cuando concurren circunstancias graves o razones de manifiesta utilidad.", plainLanguageExplanation: "Establece el régimen de indivisión impuesta por el testador. El testador puede imponer a sus herederos, aun legitimarios, la indivisión de la herencia por un plazo no mayor de diez años.", practicalEffects: ['En la práctica, este artículo rige indivisión impuesta por el testador. El testador puede imponer a sus herederos, aun legitimarios, la indivisión de la herencia por un plazo no mayor de diez años.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['indivisin', 'impuesta', 'testador', 'articulo 2330'], segments: [], amendments: [] },
  { id: 'ccyc-art-2331', lawId: 'codigo-civil-comercial', number: '2331', order: 2331, title: "Pacto de indivisión", text: "Pacto de indivisión. Los herederos pueden convenir que la indivisión entre ellos perdure total o parcialmente por un plazo que no exceda de diez años, sin perjuicio de la partición provisional de uso y goce de los bienes entre los copartícipes. Si hay herederos incapaces o con capacidad restringida, el convenio concluido por sus representantes legales o con la participación de las personas que los asisten requiere aprobación judicial. Estos convenios pueden ser renovados por igual plazo al término del anteriormente establecido. Cualquiera de los coherederos puede pedir la división antes del vencimiento del plazo, siempre que medien causas justificadas.", plainLanguageExplanation: "Establece el régimen de pacto de indivisión. Los herederos pueden convenir que la indivisión entre ellos perdure total o parcialmente por un plazo que no exceda de diez años, sin perjuicio de la partición provisional de uso y goce de los bienes entre los copartícipes.", practicalEffects: ['En la práctica, este artículo rige pacto de indivisión. Los herederos pueden convenir que la indivisión entre ellos perdure total o parcialmente por un plazo que no exceda de diez años, sin perjuicio de la'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pacto', 'indivisin', 'articulo 2331'], segments: [], amendments: [] },
  { id: 'ccyc-art-2332', lawId: 'codigo-civil-comercial', number: '2332', order: 2332, title: "Oposición del cónyuge", text: "Oposición del cónyuge. Si en el acervo hereditario existe un establecimiento comercial, industrial, agrícola, ganadero, minero o de otra índole que constituye una unidad económica, o partes sociales, cuotas o acciones de una sociedad, el cónyuge supérstite que ha adquirido o constituido en todo o en parte el establecimiento o que es el principal socio o accionista de la sociedad, puede oponerse a que se incluyan en la partición, excepto que puedan serle adjudicados en su lote. Tiene el mismo derecho el cónyuge que no adquirió ni constituyó el establecimiento pero que participa activamente en su explotación. En estos casos, la indivisión se mantiene hasta diez años a partir de la muerte del causante, pero puede ser prorrogada judicialmente a pedido del cónyuge sobreviviente hasta su fallecimiento. Durante la indivisión, la administración del establecimiento, de las partes sociales, cuotas o acciones corresponde al cónyuge sobreviviente. A instancia de cualquiera de los herederos, el juez puede autorizar el cese de la indivisión antes del plazo fijado, si concurren causas graves o de manifiesta utilidad económica que justifican la decisión. El cónyuge supérstite también puede oponerse a que la vivienda que ha sido residencia habitual de los cónyuges al tiempo de fallecer el causante y que ha sido adquirida o construida total o parcialmente con fondos gananciales, con sus muebles, sea incluida en la partición, mientras él sobreviva, excepto que pueda serle adjudicada en su lote. Los herederos sólo pueden pedir el cese de la indivisión si el cónyuge supérstite tiene bienes que le permiten procurarse otra vivienda suficiente para sus necesidades.", plainLanguageExplanation: "Establece el régimen de oposición del cónyuge. Si en el acervo hereditario existe un establecimiento comercial, industrial, agrícola, ganadero, minero o de otra índole que constituye una unidad económica, o partes sociales, cuotas o acciones de una sociedad, el cónyuge supérstite que ha adquirido o constituido en todo o en pa", practicalEffects: ['En la práctica, este artículo rige oposición del cónyuge. Si en el acervo hereditario existe un establecimiento comercial, industrial, agrícola, ganadero, minero o de otra índole que constituye una unidad eco'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oposicin', 'cnyuge', 'articulo 2332'], segments: [], amendments: [] },
  { id: 'ccyc-art-2333', lawId: 'codigo-civil-comercial', number: '2333', order: 2333, title: "Oposición de un heredero", text: "Oposición de un heredero. En las mismas circunstancias que las establecidas en el artículo 2332, un heredero puede oponerse a la inclusión en la partición del establecimiento que constituye una unidad económica si, antes de la muerte del causante, ha participado activamente en la explotación de la empresa.", plainLanguageExplanation: "Establece el régimen de oposición de un heredero. En las mismas circunstancias que las establecidas en el artículo 2332, un heredero puede oponerse a la inclusión en la partición del establecimiento que constituye una unidad económica si, antes de la muerte del causante, ha participado activamente en la explotación de la empresa", practicalEffects: ['En la práctica, este artículo rige oposición de un heredero. En las mismas circunstancias que las establecidas en el artículo 2332, un heredero puede oponerse a la inclusión en la partición del establecimiento q'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oposicin', 'heredero', 'articulo 2333'], segments: [], amendments: [] },
  { id: 'ccyc-art-2334', lawId: 'codigo-civil-comercial', number: '2334', order: 2334, title: "Oponibilidad frente a terceros", text: "Oponibilidad frente a terceros. Derechos de los acreedores. Para ser oponible a terceros, la indivisión autorizada por los artículos 2330 a 2333 que incluye bienes registrables debe ser inscripta en los registros respectivos. Durante la indivisión, los acreedores de los coherederos no pueden ejecutar el bien indiviso ni una porción ideal de éste, pero pueden cobrar sus créditos con las utilidades de la explotación correspondientes a su deudor. Las indivisiones no impiden el derecho de los acreedores del causante al cobro de sus créditos sobre los bienes indivisos. TITULO VII Proceso sucesorio CAPITULO 1 Disposiciones generales", plainLanguageExplanation: "Establece el régimen de oponibilidad frente a terceros. Derechos de los acreedores.", practicalEffects: ['En la práctica, este artículo rige oponibilidad frente a terceros. Derechos de los acreedores.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oponibilidad', 'frente', 'terceros', 'articulo 2334'], segments: [], amendments: [] },
  { id: 'ccyc-art-2335', lawId: 'codigo-civil-comercial', number: '2335', order: 2335, title: "Objeto", text: "Objeto. El proceso sucesorio tiene por objeto identificar a los sucesores, determinar el contenido de la herencia, cobrar los créditos, pagar las deudas, legados y cargas, rendir cuentas y entregar los bienes.", plainLanguageExplanation: "Establece el régimen de objeto. El proceso sucesorio tiene por objeto identificar a los sucesores, determinar el contenido de la herencia, cobrar los créditos, pagar las deudas, legados y cargas, rendir cuentas y entregar los bienes.", practicalEffects: ['En la práctica, este artículo rige objeto. El proceso sucesorio tiene por objeto identificar a los sucesores, determinar el contenido de la herencia, cobrar los créditos, pagar las deudas, lega'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['objetoarticulo 2335'], segments: [], amendments: [] },
  { id: 'ccyc-art-2336', lawId: 'codigo-civil-comercial', number: '2336', order: 2336, title: "Competencia", text: "Competencia. La competencia para entender en el juicio sucesorio corresponde al juez del último domicilio del causante, sin perjuicio de lo dispuesto en la Sección 9a, Capítulo 3, Título IV del Libro Sexto. El mismo juez conoce de las acciones de petición de herencia, nulidad de testamento, de los demás litigios que tienen lugar con motivo de la administración y liquidación de la herencia, de la ejecución de las disposiciones testamentarias, del mantenimiento de la indivisión, de las operaciones de partición, de la garantía de los lotes entre los copartícipes y de la reforma y nulidad de la partición. Si el causante deja sólo un heredero, las acciones personales de los acreedores del causante pueden dirigirse, a su opción, ante el juez del último domicilio del causante o ante el que corresponde al domicilio del heredero único. CAPITULO 2 Investidura de la calidad de heredero", plainLanguageExplanation: "Establece el régimen de competencia. La competencia para entender en el juicio sucesorio corresponde al juez del último domicilio del causante, sin perjuicio de lo dispuesto en la Sección 9a, Capítulo 3, Título IV del Libro Sexto.", practicalEffects: ['En la práctica, este artículo rige competencia. La competencia para entender en el juicio sucesorio corresponde al juez del último domicilio del causante, sin perjuicio de lo dispuesto en la Sección 9a, Capítulo 3, Título IV del Libro Sexto.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['competenciaarticulo 2336'], segments: [], amendments: [] },
  { id: 'ccyc-art-2337', lawId: 'codigo-civil-comercial', number: '2337', order: 2337, title: "Investidura de pleno derecho", text: "Investidura de pleno derecho. Si la sucesión tiene lugar entre ascendientes, descendientes y cónyuge, el heredero queda investido de su calidad de tal desde el día de la muerte del causante, sin ninguna formalidad o intervención de los jueces, aunque ignore la apertura de la sucesión y su llamamiento a la herencia. Puede ejercer todas las acciones transmisibles que correspondían al causante. No obstante, a los fines de la transferencia de los bienes registrables, su investidura debe ser reconocida mediante la declaratoria judicial de herederos.", plainLanguageExplanation: "Establece el régimen de investidura de pleno derecho. Si la sucesión tiene lugar entre ascendientes, descendientes y cónyuge, el heredero queda investido de su calidad de tal desde el día de la muerte del causante, sin ninguna formalidad o intervención de los jueces, aunque ignore la apertura de la sucesión y su llamamiento a la herencia.", practicalEffects: ['En la práctica, este artículo rige investidura de pleno derecho. Si la sucesión tiene lugar entre ascendientes, descendientes y cónyuge, el heredero queda investido de su calidad de tal desde el día de la muerte del'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['investidura', 'pleno', 'derecho', 'articulo 2337'], segments: [], amendments: [] },
  { id: 'ccyc-art-2338', lawId: 'codigo-civil-comercial', number: '2338', order: 2338, title: "Facultades judiciales", text: "Facultades judiciales. En la sucesión de los colaterales, corresponde al juez del juicio sucesorio investir a los herederos de su carácter de tales, previa justificación del fallecimiento del causante y del título hereditario invocado. En las sucesiones testamentarias, la investidura resulta de la declaración de validez formal del testamento, excepto para los herederos enumerados en el primer párrafo del artículo 2337.", plainLanguageExplanation: "Establece el régimen de facultades judiciales. En la sucesión de los colaterales, corresponde al juez del juicio sucesorio investir a los herederos de su carácter de tales, previa justificación del fallecimiento del causante y del título hereditario invocado.", practicalEffects: ['En la práctica, este artículo rige facultades judiciales. En la sucesión de los colaterales, corresponde al juez del juicio sucesorio investir a los herederos de su carácter de tales, previa justificación del'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['facultades', 'judiciales', 'articulo 2338'], segments: [], amendments: [] },
  { id: 'ccyc-art-2339', lawId: 'codigo-civil-comercial', number: '2339', order: 2339, title: "Sucesión testamentaria", text: "Sucesión testamentaria. Si el causante ha dejado testamento por acto público, debe presentárselo o indicarse el lugar donde se encuentre. Si el testamento es ológrafo, debe ser presentado judicialmente para que se proceda, previa apertura si estuviese cerrado, a dejar constancia del estado del documento, y a la comprobación de la autenticidad de la escritura y la firma del testador, mediante pericia caligráfica. Cumplidos estos trámites, el juez debe rubricar el principio y fin de cada una de sus páginas y mandar a protocolizarlo. Asimismo, si algún interesado lo pide, se le debe dar copia certificada del testamento. La protocolización no impide que sean impugnadas la autenticidad ni la validez del testamento mediante proceso contencioso.", plainLanguageExplanation: "Establece el régimen de sucesión testamentaria. Si el causante ha dejado testamento por acto público, debe presentárselo o indicarse el lugar donde se encuentre.", practicalEffects: ['En la práctica, este artículo rige sucesión testamentaria. Si el causante ha dejado testamento por acto público, debe presentárselo o indicarse el lugar donde se encuentre.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sucesin', 'testamentaria', 'articulo 2339'], segments: [], amendments: [] },
  { id: 'ccyc-art-2340', lawId: 'codigo-civil-comercial', number: '2340', order: 2340, title: "Sucesión intestada", text: "Sucesión intestada. Si no hay testamento, o éste no dispone de la totalidad de los bienes, el interesado debe expresar si el derecho que pretende es exclusivo, o si concurren otros herederos. Justificado el fallecimiento, se notifica a los herederos denunciados en el expediente, y se dispone la citación de herederos, acreedores y de todos los que se consideren con derecho a los bienes dejados por el causante, por edicto publicado por un día en el diario de publicaciones oficiales, para que lo acrediten dentro de los treinta días. CAPITULO 3 Inventario y avalúo", plainLanguageExplanation: "Establece el régimen de sucesión intestada. Si no hay testamento, o éste no dispone de la totalidad de los bienes, el interesado debe expresar si el derecho que pretende es exclusivo, o si concurren otros herederos.", practicalEffects: ['En la práctica, este artículo rige sucesión intestada. Si no hay testamento, o éste no dispone de la totalidad de los bienes, el interesado debe expresar si el derecho que pretende es exclusivo, o si concurren otros herederos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['sucesin', 'intestada', 'articulo 2340'], segments: [], amendments: [] },
  { id: 'ccyc-art-2341', lawId: 'codigo-civil-comercial', number: '2341', order: 2341, title: "Inventario", text: "Inventario. El inventario debe hacerse con citación de los herederos, acreedores y legatarios cuyo domicilio sea conocido. El inventario debe ser realizado en un plazo de tres meses desde que los acreedores o legatarios hayan intimado judicialmente a los herederos a su realización.", plainLanguageExplanation: "Establece el régimen de inventario. El inventario debe hacerse con citación de los herederos, acreedores y legatarios cuyo domicilio sea conocido.", practicalEffects: ['En la práctica, este artículo rige inventario. El inventario debe hacerse con citación de los herederos, acreedores y legatarios cuyo domicilio sea conocido.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['inventarioarticulo 2341'], segments: [], amendments: [] },
  { id: 'ccyc-art-2342', lawId: 'codigo-civil-comercial', number: '2342', order: 2342, title: "Denuncia de bienes", text: "Denuncia de bienes. Por la voluntad unánime de los copropietarios de la masa indivisa, el inventario puede ser sustituido por la denuncia de bienes, excepto que el inventario haya sido pedido por acreedores o lo imponga otra disposición de la ley.", plainLanguageExplanation: "Establece el régimen de denuncia de bienes. Por la voluntad unánime de los copropietarios de la masa indivisa, el inventario puede ser sustituido por la denuncia de bienes, excepto que el inventario haya sido pedido por acreedores o lo imponga otra disposición de la ley.", practicalEffects: ['En la práctica, este artículo rige denuncia de bienes. Por la voluntad unánime de los copropietarios de la masa indivisa, el inventario puede ser sustituido por la denuncia de bienes, excepto que el invent'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['denuncia', 'bienes', 'articulo 2342'], segments: [], amendments: [] },
  { id: 'ccyc-art-2343', lawId: 'codigo-civil-comercial', number: '2343', order: 2343, title: "Avalúo", text: "Avalúo. La valuación debe hacerse por quien designen los copropietarios de la masa indivisa, si están de acuerdo y son todos plenamente capaces o, en caso contrario, por quien designa el juez, de acuerdo a la ley local. El valor de los bienes se debe fijar a la época más próxima posible al acto de partición.", plainLanguageExplanation: "Establece el régimen de avalúo. La valuación debe hacerse por quien designen los copropietarios de la masa indivisa, si están de acuerdo y son todos plenamente capaces o, en caso contrario, por quien designa el juez, de acuerdo a la ley local.", practicalEffects: ['En la práctica, este artículo rige avalúo. La valuación debe hacerse por quien designen los copropietarios de la masa indivisa, si están de acuerdo y son todos plenamente capaces o, en caso con'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['avaloarticulo 2343'], segments: [], amendments: [] },
  { id: 'ccyc-art-2344', lawId: 'codigo-civil-comercial', number: '2344', order: 2344, title: "Impugnaciones", text: "Impugnaciones. Los copropietarios de la masa indivisa, los acreedores y legatarios pueden impugnar total o parcialmente el inventario y el avalúo o la denuncia de bienes. Si se demuestra que no es conforme al valor de los bienes, se ordena la retasa total o parcial de éstos. CAPITULO 4 Administración judicial de la sucesión SECCION 1ª Designación, derechos y deberes del administrador", plainLanguageExplanation: "Establece el régimen de impugnaciones. Los copropietarios de la masa indivisa, los acreedores y legatarios pueden impugnar total o parcialmente el inventario y el avalúo o la denuncia de bienes.", practicalEffects: ['En la práctica, este artículo rige impugnaciones. Los copropietarios de la masa indivisa, los acreedores y legatarios pueden impugnar total o parcialmente el inventario y el avalúo o la denuncia de bienes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['impugnacionesarticulo 2344'], segments: [], amendments: [] },
  { id: 'ccyc-art-2345', lawId: 'codigo-civil-comercial', number: '2345', order: 2345, title: "Capacidad", text: "Capacidad. Las personas humanas plenamente capaces, y las personas jurídicas autorizadas por la ley o los estatutos para administrar bienes ajenos, pueden ejercer el cargo de administrador.", plainLanguageExplanation: "Establece el régimen de capacidad. Las personas humanas plenamente capaces, y las personas jurídicas autorizadas por la ley o los estatutos para administrar bienes ajenos, pueden ejercer el cargo de administrador.", practicalEffects: ['En la práctica, este artículo rige capacidad. Las personas humanas plenamente capaces, y las personas jurídicas autorizadas por la ley o los estatutos para administrar bienes ajenos, pueden ejerce'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['capacidadarticulo 2345'], segments: [], amendments: [] },
  { id: 'ccyc-art-2346', lawId: 'codigo-civil-comercial', number: '2346', order: 2346, title: "Designación de administrador", text: "Designación de administrador. Los copropietarios de la masa indivisa pueden designar administrador de la herencia y proveer el modo de reemplazarlo. A falta de mayoría, cualquiera de las partes puede solicitar judicialmente su designación, la que debe recaer preferentemente, de no haber motivos que justifiquen otra decisión, sobre el cónyuge sobreviviente y, a falta, renuncia o carencia de idoneidad de éste, en alguno de los herederos, excepto que haya razones especiales que lo hagan inconveniente, caso en el cual puede designar a un extraño.", plainLanguageExplanation: "Establece el régimen de designación de administrador. Los copropietarios de la masa indivisa pueden designar administrador de la herencia y proveer el modo de reemplazarlo.", practicalEffects: ['En la práctica, este artículo rige designación de administrador. Los copropietarios de la masa indivisa pueden designar administrador de la herencia y proveer el modo de reemplazarlo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['designacin', 'administrador', 'articulo 2346'], segments: [], amendments: [] },
  { id: 'ccyc-art-2347', lawId: 'codigo-civil-comercial', number: '2347', order: 2347, title: "Designación por el testador", text: "Designación por el testador. El testador puede designar uno o varios administradores y establecer el modo de su reemplazo. Se considera nombrado administrador a quien el testador haya señalado expresamente como tal, o lo haya designado como liquidador de la sucesión, albacea, ejecutor testamentario o de otra manera similar.", plainLanguageExplanation: "Establece el régimen de designación por el testador. El testador puede designar uno o varios administradores y establecer el modo de su reemplazo.", practicalEffects: ['En la práctica, este artículo rige designación por el testador. El testador puede designar uno o varios administradores y establecer el modo de su reemplazo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['designacin', 'testador', 'articulo 2347'], segments: [], amendments: [] },
  { id: 'ccyc-art-2348', lawId: 'codigo-civil-comercial', number: '2348', order: 2348, title: "Pluralidad de administradores", text: "Pluralidad de administradores. En caso de pluralidad de administradores, el cargo es ejercido por cada uno de los nombrados en el orden en que están designados, excepto que en la designación se haya dispuesto que deben actuar conjuntamente. En caso de designación conjunta, si media impedimento de alguno de ellos, los otros pueden actuar solos para los actos conservatorios y urgentes.", plainLanguageExplanation: "Establece el régimen de pluralidad de administradores. En caso de pluralidad de administradores, el cargo es ejercido por cada uno de los nombrados en el orden en que están designados, excepto que en la designación se haya dispuesto que deben actuar conjuntamente.", practicalEffects: ['En la práctica, este artículo rige pluralidad de administradores. En caso de pluralidad de administradores, el cargo es ejercido por cada uno de los nombrados en el orden en que están designados, excepto que en la de'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['pluralidad', 'administradores', 'articulo 2348'], segments: [], amendments: [] },
  { id: 'ccyc-art-2349', lawId: 'codigo-civil-comercial', number: '2349', order: 2349, title: "Remuneración y gastos", text: "Remuneración y gastos. El administrador tiene derecho a que se le reembolsen los gastos necesarios y útiles realizados en el cumplimiento de su función. También tiene derecho a remuneración. Si no ha sido fijada por el testador, ni hay acuerdo entre el administrador y los copropietarios de la masa indivisa, debe ser determinada por el juez.", plainLanguageExplanation: "Establece el régimen de remuneración y gastos. El administrador tiene derecho a que se le reembolsen los gastos necesarios y útiles realizados en el cumplimiento de su función.", practicalEffects: ['En la práctica, este artículo rige remuneración y gastos. El administrador tiene derecho a que se le reembolsen los gastos necesarios y útiles realizados en el cumplimiento de su función.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remuneracin', 'gastos', 'articulo 2349'], segments: [], amendments: [] },
  { id: 'ccyc-art-2350', lawId: 'codigo-civil-comercial', number: '2350', order: 2350, title: "Garantías", text: "Garantías. El administrador no está obligado a garantizar el cumplimiento de sus obligaciones, excepto que el testador o la mayoría de los copropietarios de la masa indivisa lo exija, o que lo ordene el juez a pedido de interesado que demuestre la necesidad de la medida. Si requerida la garantía, el administrador omite constituirla o se rehúsa a hacerlo en el plazo fijado por el juez, debe ser removido del cargo.", plainLanguageExplanation: "Establece el régimen de garantías. El administrador no está obligado a garantizar el cumplimiento de sus obligaciones, excepto que el testador o la mayoría de los copropietarios de la masa indivisa lo exija, o que lo ordene el juez a pedido de interesado que demuestre la necesidad de la medida.", practicalEffects: ['En la práctica, este artículo rige garantías. El administrador no está obligado a garantizar el cumplimiento de sus obligaciones, excepto que el testador o la mayoría de los copropietarios de la m'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garantasarticulo 2350'], segments: [], amendments: [] },
  { id: 'ccyc-art-2351', lawId: 'codigo-civil-comercial', number: '2351', order: 2351, title: "Remoción", text: "Remoción. Todo interesado puede solicitar al juez la remoción del administrador si existe imposibilidad de ejercer el cargo o mal desempeño de éste. Mientras tramite el pedido, que se sustancia por la vía más breve que permite la legislación procesal, continúa en el ejercicio de sus funciones si el juez no resuelve designar un administrador provisional.", plainLanguageExplanation: "Establece el régimen de remoción. Todo interesado puede solicitar al juez la remoción del administrador si existe imposibilidad de ejercer el cargo o mal desempeño de éste.", practicalEffects: ['En la práctica, este artículo rige remoción. Todo interesado puede solicitar al juez la remoción del administrador si existe imposibilidad de ejercer el cargo o mal desempeño de éste.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['remocinarticulo 2351'], segments: [], amendments: [] },
  { id: 'ccyc-art-2352', lawId: 'codigo-civil-comercial', number: '2352', order: 2352, title: "Medidas urgentes", text: "Medidas urgentes. Si el administrador no ha sido aún designado, rehúsa el cargo, demora en aceptarlo o debe ser reemplazado, cualquier interesado puede solicitar medidas urgentes tendientes a asegurar sus derechos, como la facción de inventario, el depósito de bienes, y toda otra medida que el juez considere conveniente para la seguridad de éstos o la designación de administrador provisional. Los gastos que ocasionan estas medidas están a cargo de la masa indivisa. SECCION 2ª Funciones del administrador", plainLanguageExplanation: "Establece el régimen de medidas urgentes. Si el administrador no ha sido aún designado, rehúsa el cargo, demora en aceptarlo o debe ser reemplazado, cualquier interesado puede solicitar medidas urgentes tendientes a asegurar sus derechos, como la facción de inventario, el depósito de bienes, y toda otra medida que el jue", practicalEffects: ['En la práctica, este artículo rige medidas urgentes. Si el administrador no ha sido aún designado, rehúsa el cargo, demora en aceptarlo o debe ser reemplazado, cualquier interesado puede solicitar medida'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['medidas', 'urgentes', 'articulo 2352'], segments: [], amendments: [] },
  { id: 'ccyc-art-2353', lawId: 'codigo-civil-comercial', number: '2353', order: 2353, title: "Administración de los bienes", text: "Administración de los bienes. El administrador debe realizar los actos conservatorios de los bienes y continuar el giro normal de los negocios del causante. Puede, por sí solo, enajenar las cosas muebles susceptibles de perecer, depreciarse rápidamente o cuya conservación es manifiestamente onerosa. Para la enajenación de otros bienes, necesita acuerdo unánime de los herederos o, en su defecto, autorización judicial. Además de gestionar los bienes de la herencia, debe promover su realización en la medida necesaria para el pago de las deudas y legados.", plainLanguageExplanation: "Establece el régimen de administración de los bienes. El administrador debe realizar los actos conservatorios de los bienes y continuar el giro normal de los negocios del causante.", practicalEffects: ['En la práctica, este artículo rige administración de los bienes. El administrador debe realizar los actos conservatorios de los bienes y continuar el giro normal de los negocios del causante.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['administracin', 'bienes', 'articulo 2353'], segments: [], amendments: [] },
  { id: 'ccyc-art-2354', lawId: 'codigo-civil-comercial', number: '2354', order: 2354, title: "Cobro de créditos y acciones judiciales", text: "Cobro de créditos y acciones judiciales. Previa autorización judicial o de los copartícipes si son plenamente capaces y están presentes, el administrador debe cobrar los créditos del causante, continuar las acciones promovidas por éste, iniciar las que son necesarias para hacer efectivos sus derechos, y presentarse en los procesos en los cuales el causante fue demandado. En ningún caso puede realizar actos que importan disposición de los derechos del causante.", plainLanguageExplanation: "Establece el régimen de cobro de créditos y acciones judiciales. Previa autorización judicial o de los copartícipes si son plenamente capaces y están presentes, el administrador debe cobrar los créditos del causante, continuar las acciones promovidas por éste, iniciar las que son necesarias para hacer efectivos sus derechos, y presentarse en l", practicalEffects: ['En la práctica, este artículo rige cobro de créditos y acciones judiciales. Previa autorización judicial o de los copartícipes si son plenamente capaces y están presentes, el administrador debe cobrar los créditos del causante'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cobro', 'crditos', 'acciones', 'judiciales', 'articulo 2354'], segments: [], amendments: [] },
  { id: 'ccyc-art-2355', lawId: 'codigo-civil-comercial', number: '2355', order: 2355, title: "Rendición de cuentas", text: "Rendición de cuentas. Excepto que la mayoría de los copropietarios de la masa indivisa haya acordado otro plazo, el administrador de la herencia debe rendir cuentas de su administración trimestralmente, o con la periodicidad que el juez establezca. CAPITULO 5 Pago de deudas y legados", plainLanguageExplanation: "Establece el régimen de rendición de cuentas. Excepto que la mayoría de los copropietarios de la masa indivisa haya acordado otro plazo, el administrador de la herencia debe rendir cuentas de su administración trimestralmente, o con la periodicidad que el juez establezca.", practicalEffects: ['En la práctica, este artículo rige rendición de cuentas. Excepto que la mayoría de los copropietarios de la masa indivisa haya acordado otro plazo, el administrador de la herencia debe rendir cuentas de su a'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['rendicin', 'cuentas', 'articulo 2355'], segments: [], amendments: [] },
  { id: 'ccyc-art-2356', lawId: 'codigo-civil-comercial', number: '2356', order: 2356, title: "Presentación de los acreedores", text: "Presentación de los acreedores. Los acreedores hereditarios que no son titulares de garantías reales deben presentarse a la sucesión y denunciar sus créditos a fin de ser pagados. Los créditos cuyos montos no se encuentran definitivamente fijados se denuncian a título provisorio sobre la base de una estimación.", plainLanguageExplanation: "Establece el régimen de presentación de los acreedores. Los acreedores hereditarios que no son titulares de garantías reales deben presentarse a la sucesión y denunciar sus créditos a fin de ser pagados.", practicalEffects: ['En la práctica, este artículo rige presentación de los acreedores. Los acreedores hereditarios que no son titulares de garantías reales deben presentarse a la sucesión y denunciar sus créditos a fin de ser pagados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['presentacin', 'acreedores', 'articulo 2356'], segments: [], amendments: [] },
  { id: 'ccyc-art-2357', lawId: 'codigo-civil-comercial', number: '2357', order: 2357, title: "Declaración de legítimo abono", text: "Declaración de legítimo abono. Los herederos pueden reconocer a los acreedores del causante que solicitan la declaración de legítimo abono de sus créditos. Emitida tal declaración por el juez, el acreedor reconocido debe ser pagado según el orden establecido por el artículo siguiente. A falta de reconocimiento expreso y unánime de los herederos, el acreedor está facultado para deducir las acciones que le corresponden.", plainLanguageExplanation: "Establece el régimen de declaración de legítimo abono. Los herederos pueden reconocer a los acreedores del causante que solicitan la declaración de legítimo abono de sus créditos.", practicalEffects: ['En la práctica, este artículo rige declaración de legítimo abono. Los herederos pueden reconocer a los acreedores del causante que solicitan la declaración de legítimo abono de sus créditos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['declaracin', 'legtimo', 'abono', 'articulo 2357'], segments: [], amendments: [] },
  { id: 'ccyc-art-2358', lawId: 'codigo-civil-comercial', number: '2358', order: 2358, title: "Procedimiento de pago", text: "Procedimiento de pago. El administrador debe pagar a los acreedores presentados según el rango de preferencia de cada crédito establecido en la ley de concursos. Pagados los acreedores, los legados se cumplen, en los límites de la porción disponible, en el siguiente orden: a) los que tienen preferencia otorgada por el testamento; b) los de cosa cierta y determinada; c) los demás legados. Si hay varios de la misma categoría, se pagan a prorrata.", plainLanguageExplanation: "Establece el régimen de procedimiento de pago. El administrador debe pagar a los acreedores presentados según el rango de preferencia de cada crédito establecido en la ley de concursos.", practicalEffects: ['En la práctica, este artículo rige procedimiento de pago. El administrador debe pagar a los acreedores presentados según el rango de preferencia de cada crédito establecido en la ley de concursos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['procedimiento', 'pago', 'articulo 2358'], segments: [], amendments: [] },
  { id: 'ccyc-art-2359', lawId: 'codigo-civil-comercial', number: '2359', order: 2359, title: "Garantía de los acreedores y legatarios de la sucesión", text: "Garantía de los acreedores y legatarios de la sucesión. Los acreedores del causante, los acreedores por cargas de la masa y los legatarios pueden oponerse a la entrega de los bienes a los herederos hasta el pago de sus créditos o legados.", plainLanguageExplanation: "Establece el régimen de garantía de los acreedores y legatarios de la sucesión. Los acreedores del causante, los acreedores por cargas de la masa y los legatarios pueden oponerse a la entrega de los bienes a los herederos hasta el pago de sus créditos o legados.", practicalEffects: ['En la práctica, este artículo rige garantía de los acreedores y legatarios de la sucesión. Los acreedores del causante, los acreedores por cargas de la masa y los legatarios pueden oponerse a la entrega de los bienes a los herederos hasta el'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garanta', 'acreedores', 'legatarios', 'sucesin', 'articulo 2359'], segments: [], amendments: [] },
  { id: 'ccyc-art-2360', lawId: 'codigo-civil-comercial', number: '2360', order: 2360, title: "Masa indivisa insolvente", text: "Masa indivisa insolvente. En caso de desequilibrio patrimonial o insuficiencia del activo hereditario, los copropietarios de la masa pueden peticionar la apertura del concurso preventivo o la declaración de quiebra de la masa indivisa, conforme a las disposiciones de la legislación concursal. Igual derecho, y de acuerdo a la misma normativa, compete a los acreedores. CAPITULO 6 Conclusión de la administración judicial", plainLanguageExplanation: "Establece el régimen de masa indivisa insolvente. En caso de desequilibrio patrimonial o insuficiencia del activo hereditario, los copropietarios de la masa pueden peticionar la apertura del concurso preventivo o la declaración de quiebra de la masa indivisa, conforme a las disposiciones de la legislación concursal.", practicalEffects: ['En la práctica, este artículo rige masa indivisa insolvente. En caso de desequilibrio patrimonial o insuficiencia del activo hereditario, los copropietarios de la masa pueden peticionar la apertura del concurso'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['masa', 'indivisa', 'insolvente', 'articulo 2360'], segments: [], amendments: [] },
  { id: 'ccyc-art-2361', lawId: 'codigo-civil-comercial', number: '2361', order: 2361, title: "Cuenta definitiva", text: "Cuenta definitiva. Concluida la administración, el administrador debe presentar la cuenta definitiva.", plainLanguageExplanation: "Establece el régimen de cuenta definitiva. Concluida la administración, el administrador debe presentar la cuenta definitiva.", practicalEffects: ['En la práctica, este artículo rige cuenta definitiva. Concluida la administración, el administrador debe presentar la cuenta definitiva.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cuenta', 'definitiva', 'articulo 2361'], segments: [], amendments: [] },
  { id: 'ccyc-art-2362', lawId: 'codigo-civil-comercial', number: '2362', order: 2362, title: "Forma de la cuenta", text: "Forma de la cuenta. Si todos los copropietarios de la masa indivisa son plenamente capaces y están de acuerdo, la rendición de cuentas se hace privadamente, quedando los gastos a cargo de la masa indivisa. En caso contrario, debe hacerse judicialmente. De ella se debe dar vista a los copropietarios de la masa indivisa, quienes pueden impugnarla. TITULO VIII Partición CAPITULO 1 Acción de partición", plainLanguageExplanation: "Establece el régimen de forma de la cuenta. Si todos los copropietarios de la masa indivisa son plenamente capaces y están de acuerdo, la rendición de cuentas se hace privadamente, quedando los gastos a cargo de la masa indivisa.", practicalEffects: ['En la práctica, este artículo rige forma de la cuenta. Si todos los copropietarios de la masa indivisa son plenamente capaces y están de acuerdo, la rendición de cuentas se hace privadamente, quedando los gastos a cargo de la masa indivisa.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['forma', 'cuenta', 'articulo 2362'], segments: [], amendments: [] },
  { id: 'ccyc-art-2363', lawId: 'codigo-civil-comercial', number: '2363', order: 2363, title: "Conclusión de la indivisión", text: "Conclusión de la indivisión. La indivisión hereditaria sólo cesa con la partición. Si la partición incluye bienes registrables, es oponible a los terceros desde su inscripción en los registros respectivos.", plainLanguageExplanation: "Establece el régimen de conclusión de la indivisión. La indivisión hereditaria sólo cesa con la partición.", practicalEffects: ['En la práctica, este artículo rige conclusión de la indivisión. La indivisión hereditaria sólo cesa con la partición.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['conclusin', 'indivisin', 'articulo 2363'], segments: [], amendments: [] },
  { id: 'ccyc-art-2364', lawId: 'codigo-civil-comercial', number: '2364', order: 2364, title: "Legitimación", text: "Legitimación. Pueden pedir la partición los copropietarios de la masa indivisa y los cesionarios de sus derechos. También pueden hacerlo, por vía de subrogación, sus acreedores, y los beneficiarios de legados o cargos que pesan sobre un heredero. En caso de muerte de un heredero, o de cesión de sus derechos a varias personas, cualquiera de los herederos o cesionarios puede pedir la partición; pero si todos ellos lo hacen, deben unificar su representación.", plainLanguageExplanation: "Establece el régimen de legitimación. Pueden pedir la partición los copropietarios de la masa indivisa y los cesionarios de sus derechos.", practicalEffects: ['En la práctica, este artículo rige legitimación. Pueden pedir la partición los copropietarios de la masa indivisa y los cesionarios de sus derechos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['legitimacinarticulo 2364'], segments: [], amendments: [] },
  { id: 'ccyc-art-2365', lawId: 'codigo-civil-comercial', number: '2365', order: 2365, title: "Oportunidad para pedirla", text: "Oportunidad para pedirla. La partición puede ser solicitada en todo tiempo después de aprobados el inventario y avalúo de los bienes. Sin embargo, cualquiera de los copartícipes puede pedir que la partición se postergue total o parcialmente por el tiempo que fije el juez si su realización inmediata puede redundar en perjuicio del valor de los bienes indivisos.", plainLanguageExplanation: "Establece el régimen de oportunidad para pedirla. La partición puede ser solicitada en todo tiempo después de aprobados el inventario y avalúo de los bienes.", practicalEffects: ['En la práctica, este artículo rige oportunidad para pedirla. La partición puede ser solicitada en todo tiempo después de aprobados el inventario y avalúo de los bienes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['oportunidad', 'para', 'pedirla', 'articulo 2365'], segments: [], amendments: [] },
  { id: 'ccyc-art-2366', lawId: 'codigo-civil-comercial', number: '2366', order: 2366, title: "Herederos condicionales", text: "Herederos condicionales. Los herederos instituidos bajo condición suspensiva no pueden pedir la partición mientras la condición no está cumplida, pero pueden pedirla los coherederos, asegurando el derecho de los herederos condicionales. Los instituidos bajo condición resolutoria pueden pedir la partición, pero deben asegurar el derecho de quienes los sustituyen al cumplirse la condición.", plainLanguageExplanation: "Establece el régimen de herederos condicionales. Los herederos instituidos bajo condición suspensiva no pueden pedir la partición mientras la condición no está cumplida, pero pueden pedirla los coherederos, asegurando el derecho de los herederos condicionales.", practicalEffects: ['En la práctica, este artículo rige herederos condicionales. Los herederos instituidos bajo condición suspensiva no pueden pedir la partición mientras la condición no está cumplida, pero pueden pedirla los coher'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['herederos', 'condicionales', 'articulo 2366'], segments: [], amendments: [] },
  { id: 'ccyc-art-2367', lawId: 'codigo-civil-comercial', number: '2367', order: 2367, title: "Partición parcial", text: "Partición parcial. Si una parte de los bienes no es susceptible de división inmediata, se puede pedir la partición de los que son actualmente partibles.", plainLanguageExplanation: "Establece el régimen de partición parcial. Si una parte de los bienes no es susceptible de división inmediata, se puede pedir la partición de los que son actualmente partibles.", practicalEffects: ['En la práctica, este artículo rige partición parcial. Si una parte de los bienes no es susceptible de división inmediata, se puede pedir la partición de los que son actualmente partibles.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['particin', 'parcial', 'articulo 2367'], segments: [], amendments: [] },
  { id: 'ccyc-art-2368', lawId: 'codigo-civil-comercial', number: '2368', order: 2368, title: "Prescripción", text: "Prescripción. La acción de partición de herencia es imprescriptible mientras continúe la indivisión, pero hay prescripción adquisitiva larga de los bienes individuales si la indivisión ha cesado de hecho porque alguno de los copartícipes ha intervertido su título poseyéndolos como único propietario, durante el lapso que establece la ley. CAPITULO 2 Modos de hacer la partición", plainLanguageExplanation: "Establece el régimen de prescripción. La acción de partición de herencia es imprescriptible mientras continúe la indivisión, pero hay prescripción adquisitiva larga de los bienes individuales si la indivisión ha cesado de hecho porque alguno de los copartícipes ha intervertido su título poseyéndolos como único propie", practicalEffects: ['En la práctica, este artículo rige prescripción. La acción de partición de herencia es imprescriptible mientras continúe la indivisión, pero hay prescripción adquisitiva larga de los bienes individua'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['prescripcinarticulo 2368'], segments: [], amendments: [] },
  { id: 'ccyc-art-2369', lawId: 'codigo-civil-comercial', number: '2369', order: 2369, title: "Partición privada", text: "Partición privada. Si todos los copartícipes están presentes y son plenamente capaces, la partición puede hacerse en la forma y por el acto que por unanimidad juzguen convenientes. La partición puede ser total o parcial.", plainLanguageExplanation: "Establece el régimen de partición privada. Si todos los copartícipes están presentes y son plenamente capaces, la partición puede hacerse en la forma y por el acto que por unanimidad juzguen convenientes.", practicalEffects: ['En la práctica, este artículo rige partición privada. Si todos los copartícipes están presentes y son plenamente capaces, la partición puede hacerse en la forma y por el acto que por unanimidad juzguen convenientes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['particin', 'privada', 'articulo 2369'], segments: [], amendments: [] },
  { id: 'ccyc-art-2370', lawId: 'codigo-civil-comercial', number: '2370', order: 2370, title: "Partición provisional", text: "Partición provisional. La partición se considera meramente provisional si los copartícipes sólo han hecho una división del uso y goce de los bienes de la herencia, dejando indivisa la propiedad. La partición provisional no obsta al derecho de pedir la partición definitiva.", plainLanguageExplanation: "Establece el régimen de partición provisional. La partición se considera meramente provisional si los copartícipes sólo han hecho una división del uso y goce de los bienes de la herencia, dejando indivisa la propiedad.", practicalEffects: ['En la práctica, este artículo rige partición provisional. La partición se considera meramente provisional si los copartícipes sólo han hecho una división del uso y goce de los bienes de la herencia, dejando indivisa la propiedad.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['particin', 'provisional', 'articulo 2370'], segments: [], amendments: [] },
  { id: 'ccyc-art-2371', lawId: 'codigo-civil-comercial', number: '2371', order: 2371, title: "Partición judicial", text: "Partición judicial. La partición debe ser judicial: a) si hay copartícipes incapaces, con capacidad restringida o ausentes; b) si terceros, fundándose en un interés legítimo, se oponen a que la partición se haga privadamente; c) si los copartícipes son plenamente capaces y no acuerdan en hacer la partición privadamente.", plainLanguageExplanation: "Establece el régimen de partición judicial. La partición debe ser judicial: a) si hay copartícipes incapaces, con capacidad restringida o ausentes; b) si terceros, fundándose en un interés legítimo, se oponen a que la partición se haga privadamente; c) si los copartícipes son plenamente capaces y no acuerdan en hacer la pa", practicalEffects: ['En la práctica, este artículo rige partición judicial. La partición debe ser judicial: a) si hay copartícipes incapaces, con capacidad restringida o ausentes; b) si terceros, fundándose en un interés legít'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['particin', 'judicial', 'articulo 2371'], segments: [], amendments: [] },
  { id: 'ccyc-art-2372', lawId: 'codigo-civil-comercial', number: '2372', order: 2372, title: "Licitación", text: "Licitación. Cualquiera de los copartícipes puede pedir la licitación de alguno de los bienes de la herencia para que se le adjudique dentro de su hijuela por un valor superior al del avalúo, si los demás copartícipes no superan su oferta. Efectuada la licitación entre los herederos, el bien licitado debe ser imputado a la hijuela del adquirente, por el valor obtenido en la licitación, quedando de ese modo modificado el avalúo de ese bien. La oferta puede hacerse por dos o más copartícipes, caso en el cual el bien se adjudica en copropiedad a los licitantes, y se imputa proporcionalmente en la hijuela de cada uno de ellos. No puede pedirse la licitación después de pasados treinta días de la aprobación de la tasación.", plainLanguageExplanation: "Establece el régimen de licitación. Cualquiera de los copartícipes puede pedir la licitación de alguno de los bienes de la herencia para que se le adjudique dentro de su hijuela por un valor superior al del avalúo, si los demás copartícipes no superan su oferta.", practicalEffects: ['En la práctica, este artículo rige licitación. Cualquiera de los copartícipes puede pedir la licitación de alguno de los bienes de la herencia para que se le adjudique dentro de su hijuela por un v'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['licitacinarticulo 2372'], segments: [], amendments: [] },
  { id: 'ccyc-art-2373', lawId: 'codigo-civil-comercial', number: '2373', order: 2373, title: "Partidor", text: "Partidor. La partición judicial se hace por un partidor o por varios que actúan conjuntamente. A falta de acuerdo unánime de los copartícipes para su designación, el nombramiento debe ser hecho por el juez.", plainLanguageExplanation: "Establece el régimen de partidor. La partición judicial se hace por un partidor o por varios que actúan conjuntamente.", practicalEffects: ['En la práctica, este artículo rige partidor. La partición judicial se hace por un partidor o por varios que actúan conjuntamente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['partidorarticulo 2373'], segments: [], amendments: [] },
  { id: 'ccyc-art-2374', lawId: 'codigo-civil-comercial', number: '2374', order: 2374, title: "Principio de partición en especie", text: "Principio de partición en especie. Si es posible dividir y adjudicar los bienes en especie, ninguno de los copartícipes puede exigir su venta. En caso contrario, se debe proceder a la venta de los bienes y a la distribución del producto que se obtiene. También puede venderse parte de los bienes si es necesario para posibilitar la formación de los lotes.", plainLanguageExplanation: "Establece el régimen de principio de partición en especie. Si es posible dividir y adjudicar los bienes en especie, ninguno de los copartícipes puede exigir su venta.", practicalEffects: ['En la práctica, este artículo rige principio de partición en especie. Si es posible dividir y adjudicar los bienes en especie, ninguno de los copartícipes puede exigir su venta.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['principio', 'particin', 'especie', 'articulo 2374'], segments: [], amendments: [] },
  { id: 'ccyc-art-2375', lawId: 'codigo-civil-comercial', number: '2375', order: 2375, title: "División antieconómica", text: "División antieconómica. Aunque los bienes sean divisibles, no se los debe dividir si ello hace antieconómico el aprovechamiento de las partes. Si no son licitados, pueden ser adjudicados a uno o varios de los copartícipes que los acepten, compensándose en dinero la diferencia entre el valor de los bienes y el monto de las hijuelas.", plainLanguageExplanation: "Establece el régimen de división antieconómica. Aunque los bienes sean divisibles, no se los debe dividir si ello hace antieconómico el aprovechamiento de las partes.", practicalEffects: ['En la práctica, este artículo rige división antieconómica. Aunque los bienes sean divisibles, no se los debe dividir si ello hace antieconómico el aprovechamiento de las partes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['divisin', 'antieconmica', 'articulo 2375'], segments: [], amendments: [] },
  { id: 'ccyc-art-2376', lawId: 'codigo-civil-comercial', number: '2376', order: 2376, title: "Composición de la masa", text: "Composición de la masa. La masa partible comprende los bienes del causante que existen al tiempo de la partición o los que se han subrogado a ellos, y los acrecimientos de unos y otros. Se deducen las deudas y se agregan los valores que deben ser colacionados y los bienes sujetos a reducción.", plainLanguageExplanation: "Establece el régimen de composición de la masa. La masa partible comprende los bienes del causante que existen al tiempo de la partición o los que se han subrogado a ellos, y los acrecimientos de unos y otros.", practicalEffects: ['En la práctica, este artículo rige composición de la masa. La masa partible comprende los bienes del causante que existen al tiempo de la partición o los que se han subrogado a ellos, y los acrecimientos de unos y otros.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['composicin', 'masa', 'articulo 2376'], segments: [], amendments: [] },
  { id: 'ccyc-art-2377', lawId: 'codigo-civil-comercial', number: '2377', order: 2377, title: "Formación de los lotes", text: "Formación de los lotes. Para la formación de los lotes no se tiene en cuenta la naturaleza ni el destino de los bienes, excepto que sean aplicables las normas referentes a la atribución preferencial. Debe evitarse el parcelamiento de los inmuebles y la división de las empresas. Si la composición de la masa no permite formar lotes de igual valor, las diferencias entre el valor de los bienes que integran un lote y el monto de la hijuela correspondiente deben ser cubiertas con dinero, garantizándose el saldo pendiente a satisfacción del acreedor. El saldo no puede superar la mitad del valor del lote, excepto en el caso de atribución preferencial. Excepto acuerdo en contrario, si al deudor del saldo se le conceden plazos para el pago y, por circunstancias económicas, el valor de los bienes que le han sido atribuidos aumenta o disminuye apreciablemente, las sumas debidas aumentan o disminuyen en igual proporción. Si hay cosas gravadas con derechos reales de garantía, debe ponerse a cargo del adjudicatario la deuda respectiva, imputándose a la hijuela la diferencia entre el valor de la cosa y el importe de la deuda. Las sumas que deben ser colacionadas por uno de los coherederos se imputan a sus derechos sobre la masa.", plainLanguageExplanation: "Establece el régimen de formación de los lotes. Para la formación de los lotes no se tiene en cuenta la naturaleza ni el destino de los bienes, excepto que sean aplicables las normas referentes a la atribución preferencial.", practicalEffects: ['En la práctica, este artículo rige formación de los lotes. Para la formación de los lotes no se tiene en cuenta la naturaleza ni el destino de los bienes, excepto que sean aplicables las normas referentes a la atribución preferencial.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['formacin', 'lotes', 'articulo 2377'], segments: [], amendments: [] },
  { id: 'ccyc-art-2378', lawId: 'codigo-civil-comercial', number: '2378', order: 2378, title: "Asignación de los lotes", text: "Asignación de los lotes. Los lotes correspondientes a hijuelas de igual monto deben ser asignados por el partidor con la conformidad de los herederos y, en caso de oposición de alguno de éstos, por sorteo. En todo caso se deben reservar bienes suficientes para solventar las deudas y cargas pendientes, así como los legados impagos.", plainLanguageExplanation: "Establece el régimen de asignación de los lotes. Los lotes correspondientes a hijuelas de igual monto deben ser asignados por el partidor con la conformidad de los herederos y, en caso de oposición de alguno de éstos, por sorteo.", practicalEffects: ['En la práctica, este artículo rige asignación de los lotes. Los lotes correspondientes a hijuelas de igual monto deben ser asignados por el partidor con la conformidad de los herederos y, en caso de oposición de alguno de éstos, por sorteo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['asignacin', 'lotes', 'articulo 2378'], segments: [], amendments: [] },
  { id: 'ccyc-art-2379', lawId: 'codigo-civil-comercial', number: '2379', order: 2379, title: "Títulos", text: "Títulos. Objetos comunes. Los títulos de adquisición de los bienes incluidos en la partición deben ser entregados a su adjudicatario. Si algún bien es adjudicado a varios herederos, el título se entrega al propietario de la cuota mayor, y se da a los otros interesados copia certificada a costa de la masa. Los objetos y documentos que tienen un valor de afección u honorífico son indivisibles, y se debe confiar su custodia al heredero que en cada caso las partes elijan y, a falta de acuerdo, al que designa el juez. Igual solución corresponde cuando la cosa se adjudica a todos los herederos por partes iguales.", plainLanguageExplanation: "Establece el régimen de títulos. Objetos comunes.", practicalEffects: ['En la práctica, este artículo rige títulos. Objetos comunes.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['ttulosarticulo 2379'], segments: [], amendments: [] },
  { id: 'ccyc-art-2380', lawId: 'codigo-civil-comercial', number: '2380', order: 2380, title: "Atribución preferencial de establecimiento", text: "Atribución preferencial de establecimiento. El cónyuge sobreviviente o un heredero pueden pedir la atribución preferencial en la partición, con cargo de pagar el saldo si lo hay, del establecimiento agrícola, comercial, industrial, artesanal o de servicios que constituye una unidad económica, en cuya formación participó. En caso de explotación en forma social, puede pedirse la atribución preferencial de los derechos sociales, si ello no afecta las disposiciones legales o las cláusulas estatutarias sobre la continuación de una sociedad con el cónyuge sobreviviente o con uno o varios herederos. El saldo debe ser pagado al contado, excepto acuerdo en contrario.", plainLanguageExplanation: "Establece el régimen de atribución preferencial de establecimiento. El cónyuge sobreviviente o un heredero pueden pedir la atribución preferencial en la partición, con cargo de pagar el saldo si lo hay, del establecimiento agrícola, comercial, industrial, artesanal o de servicios que constituye una unidad económica, en cuya formación participó.", practicalEffects: ['En la práctica, este artículo rige atribución preferencial de establecimiento. El cónyuge sobreviviente o un heredero pueden pedir la atribución preferencial en la partición, con cargo de pagar el saldo si lo hay, del establecimi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribucin', 'preferencial', 'establecimiento', 'articulo 2380'], segments: [], amendments: [] },
  { id: 'ccyc-art-2381', lawId: 'codigo-civil-comercial', number: '2381', order: 2381, title: "Atribución preferencial de otros bienes", text: "Atribución preferencial de otros bienes. El cónyuge sobreviviente o un heredero pueden pedir también la atribución preferencial: a) de la propiedad o del derecho a la locación del inmueble que le sirve de habitación, si tenía allí su residencia al tiempo de la muerte, y de los muebles existentes en él; b) de la propiedad o del derecho a la locación del local de uso profesional donde ejercía su actividad, y de los muebles existentes en él; c) del conjunto de las cosas muebles necesarias para la explotación de un bien rural realizada por el causante como arrendatario o aparcero cuando el arrendamiento o aparcería continúa en provecho del demandante o se contrata un nuevo arrendamiento con éste.", plainLanguageExplanation: "Establece el régimen de atribución preferencial de otros bienes. El cónyuge sobreviviente o un heredero pueden pedir también la atribución preferencial: a) de la propiedad o del derecho a la locación del inmueble que le sirve de habitación, si tenía allí su residencia al tiempo de la muerte, y de los muebles existentes en él; b) de la propieda", practicalEffects: ['En la práctica, este artículo rige atribución preferencial de otros bienes. El cónyuge sobreviviente o un heredero pueden pedir también la atribución preferencial: a) de la propiedad o del derecho a la locación del inmueble qu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['atribucin', 'preferencial', 'otros', 'bienes', 'articulo 2381'], segments: [], amendments: [] },
  { id: 'ccyc-art-2382', lawId: 'codigo-civil-comercial', number: '2382', order: 2382, title: "Petición por varios interesados", text: "Petición por varios interesados. Si la atribución preferencial es solicitada por varios copartícipes que no acuerdan en que les sea asignada conjuntamente, el juez la debe decidir te-niendo en cuenta la aptitud de los postulantes para continuar la explotación y la importancia de su participación personal en la actividad.", plainLanguageExplanation: "Establece el régimen de petición por varios interesados. Si la atribución preferencial es solicitada por varios copartícipes que no acuerdan en que les sea asignada conjuntamente, el juez la debe decidir te-niendo en cuenta la aptitud de los postulantes para continuar la explotación y la importancia de su participación personal en la a", practicalEffects: ['En la práctica, este artículo rige petición por varios interesados. Si la atribución preferencial es solicitada por varios copartícipes que no acuerdan en que les sea asignada conjuntamente, el juez la debe decidir te-'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['peticin', 'varios', 'interesados', 'articulo 2382'], segments: [], amendments: [] },
  { id: 'ccyc-art-2383', lawId: 'codigo-civil-comercial', number: '2383', order: 2383, title: "Derecho real de habitación del cónyuge supérstite", text: "Derecho real de habitación del cónyuge supérstite. El cónyuge supérstite tiene derecho real de habitación vitalicio y gratuito de pleno derecho sobre el inmueble de propiedad del causante, que constituyó el último hogar conyugal, y que a la apertura de la sucesión no se encontraba en condominio con otras personas. Este derecho es inoponible a los acreedores del causante.", plainLanguageExplanation: "Establece el régimen de derecho real de habitación del cónyuge supérstite. El cónyuge supérstite tiene derecho real de habitación vitalicio y gratuito de pleno derecho sobre el inmueble de propiedad del causante, que constituyó el último hogar conyugal, y que a la apertura de la sucesión no se encontraba en condominio con otras personas.", practicalEffects: ['En la práctica, este artículo rige derecho real de habitación del cónyuge supérstite. El cónyuge supérstite tiene derecho real de habitación vitalicio y gratuito de pleno derecho sobre el inmueble de propiedad del causante, que constitu'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'real', 'habitacin', 'cnyuge', 'suprstite', 'articulo 2383'], segments: [], amendments: [] },
  { id: 'ccyc-art-2384', lawId: 'codigo-civil-comercial', number: '2384', order: 2384, title: "Cargas de la masa", text: "Cargas de la masa. Los gastos causados por la partición o liquidación, y los hechos en beneficio común, se imputan a la masa. No son comunes los trabajos o desembolsos innecesarios o referentes a pedidos desestimados, los que deben ser soportados exclusivamente por los herederos que los causen. CAPITULO 3 Colación de donaciones", plainLanguageExplanation: "Establece el régimen de cargas de la masa. Los gastos causados por la partición o liquidación, y los hechos en beneficio común, se imputan a la masa.", practicalEffects: ['En la práctica, este artículo rige cargas de la masa. Los gastos causados por la partición o liquidación, y los hechos en beneficio común, se imputan a la masa.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['cargas', 'masa', 'articulo 2384'], segments: [], amendments: [] },
  { id: 'ccyc-art-2385', lawId: 'codigo-civil-comercial', number: '2385', order: 2385, title: "Personas obligadas a colacionar", text: "Personas obligadas a colacionar. Los descendientes del causante y el cónyuge supérstite que concurren a la sucesión intestada deben colacionar a la masa hereditaria el valor de los bienes que les fueron donados por el causante, excepto dispensa o cláusula de mejora expresa en el acto de la donación o en el testamento. Dicho valor se determina a la época de la partición según el estado del bien a la época de la donación. También hay obligación de colacionar en las sucesiones testamentarias si el testador llama a recibir las mismas porciones que corresponderían al cónyuge o a los descendientes en la sucesión intestada. El legado hecho al descendiente o al cónyuge se considera realizado a título de mejora, excepto que el testador haya dispuesto expresamente lo contrario.", plainLanguageExplanation: "Establece el régimen de personas obligadas a colacionar. Los descendientes del causante y el cónyuge supérstite que concurren a la sucesión intestada deben colacionar a la masa hereditaria el valor de los bienes que les fueron donados por el causante, excepto dispensa o cláusula de mejora expresa en el acto de la donación o en el testamento.", practicalEffects: ['En la práctica, este artículo rige personas obligadas a colacionar. Los descendientes del causante y el cónyuge supérstite que concurren a la sucesión intestada deben colacionar a la masa hereditaria el valor de los bi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['personas', 'obligadas', 'colacionar', 'articulo 2385'], segments: [], amendments: [] },
  { id: 'ccyc-art-2386', lawId: 'codigo-civil-comercial', number: '2386', order: 2386, title: "Donaciones inoficiosas", text: "Donaciones inoficiosas. La donación hecha a un descendiente o al cónyuge cuyo valor excede la suma de la porción disponible más la porción legítima del donatario, aunque haya dispensa de colación o mejora, está sujeta a colación, debiendo compensarse la diferencia en dinero. (Artículo sustituido por art. 1º de la Ley Nº 27.587 B.O. 16/12/2020)", plainLanguageExplanation: "Establece el régimen de donaciones inoficiosas. La donación hecha a un descendiente o al cónyuge cuyo valor excede la suma de la porción disponible más la porción legítima del donatario, aunque haya dispensa de colación o mejora, está sujeta a colación, debiendo compensarse la diferencia en dinero.", practicalEffects: ['En la práctica, este artículo rige donaciones inoficiosas. La donación hecha a un descendiente o al cónyuge cuyo valor excede la suma de la porción disponible más la porción legítima del donatario, aunque haya'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['donaciones', 'inoficiosas', 'articulo 2386'], segments: [], amendments: [] },
  { id: 'ccyc-art-2387', lawId: 'codigo-civil-comercial', number: '2387', order: 2387, title: "Heredero renunciante", text: "Heredero renunciante. El descendiente o el cónyuge que renuncia a la herencia pueden conservar la donación recibida o reclamar el legado hecho, hasta el límite de la porción disponible.", plainLanguageExplanation: "Establece el régimen de heredero renunciante. El descendiente o el cónyuge que renuncia a la herencia pueden conservar la donación recibida o reclamar el legado hecho, hasta el límite de la porción disponible.", practicalEffects: ['En la práctica, este artículo rige heredero renunciante. El descendiente o el cónyuge que renuncia a la herencia pueden conservar la donación recibida o reclamar el legado hecho, hasta el límite de la porció'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['heredero', 'renunciante', 'articulo 2387'], segments: [], amendments: [] },
  { id: 'ccyc-art-2388', lawId: 'codigo-civil-comercial', number: '2388', order: 2388, title: "Heredero que no lo era al tiempo de la donación", text: "Heredero que no lo era al tiempo de la donación. El descendiente que no era heredero presuntivo al tiempo de la donación, pero que resulta heredero, no debe colación. El cónyuge no debe colación cuando la donación se realiza antes del matrimonio.", plainLanguageExplanation: "Establece el régimen de heredero que no lo era al tiempo de la donación. El descendiente que no era heredero presuntivo al tiempo de la donación, pero que resulta heredero, no debe colación.", practicalEffects: ['En la práctica, este artículo rige heredero que no lo era al tiempo de la donación. El descendiente que no era heredero presuntivo al tiempo de la donación, pero que resulta heredero, no debe colación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['heredero', 'tiempo', 'donacin', 'articulo 2388'], segments: [], amendments: [] },
  { id: 'ccyc-art-2389', lawId: 'codigo-civil-comercial', number: '2389', order: 2389, title: "Donación al descendiente o ascendiente del heredero", text: "Donación al descendiente o ascendiente del heredero. Las donaciones hechas a los descendientes del heredero no deben ser colacionadas por éste. El descendiente del donatario que concurre a la sucesión del donante por representación debe colacionar la donación hecha al ascendiente representado.", plainLanguageExplanation: "Establece el régimen de donación al descendiente o ascendiente del heredero. Las donaciones hechas a los descendientes del heredero no deben ser colacionadas por éste.", practicalEffects: ['En la práctica, este artículo rige donación al descendiente o ascendiente del heredero. Las donaciones hechas a los descendientes del heredero no deben ser colacionadas por éste.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['donacin', 'descendiente', 'ascendiente', 'heredero', 'articulo 2389'], segments: [], amendments: [] },
  { id: 'ccyc-art-2390', lawId: 'codigo-civil-comercial', number: '2390', order: 2390, title: "Donación al cónyuge del heredero", text: "Donación al cónyuge del heredero. Las donaciones hechas al cónyuge del heredero no deben ser colacionadas por éste. Las hechas conjuntamente a ambos cónyuges deben ser colacionadas por la mitad, por el que resulta heredero.", plainLanguageExplanation: "Establece el régimen de donación al cónyuge del heredero. Las donaciones hechas al cónyuge del heredero no deben ser colacionadas por éste.", practicalEffects: ['En la práctica, este artículo rige donación al cónyuge del heredero. Las donaciones hechas al cónyuge del heredero no deben ser colacionadas por éste.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['donacin', 'cnyuge', 'heredero', 'articulo 2390'], segments: [], amendments: [] },
  { id: 'ccyc-art-2391', lawId: 'codigo-civil-comercial', number: '2391', order: 2391, title: "Beneficios hechos al heredero", text: "Beneficios hechos al heredero. Los descendientes y el cónyuge supérstite obligados a colacionar también deben colacionar los beneficios recibidos a consecuencia de convenciones hechas con el difunto que tuvieron por objeto procurarles una ventaja particular, excepto dispensa y lo dispuesto para el heredero con discapacidad en el artículo 2448.", plainLanguageExplanation: "Establece el régimen de beneficios hechos al heredero. Los descendientes y el cónyuge supérstite obligados a colacionar también deben colacionar los beneficios recibidos a consecuencia de convenciones hechas con el difunto que tuvieron por objeto procurarles una ventaja particular, excepto dispensa y lo dispuesto para el heredero con", practicalEffects: ['En la práctica, este artículo rige beneficios hechos al heredero. Los descendientes y el cónyuge supérstite obligados a colacionar también deben colacionar los beneficios recibidos a consecuencia de convenciones hech'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['beneficios', 'hechos', 'heredero', 'articulo 2391'], segments: [], amendments: [] },
  { id: 'ccyc-art-2392', lawId: 'codigo-civil-comercial', number: '2392', order: 2392, title: "Beneficios excluidos de la colación", text: "Beneficios excluidos de la colación. No se debe colación por los gastos de alimentos; ni por los de asistencia médica por extraordinarios que sean; ni por los de educación y capacitación profesional o artística de los descendientes, excepto que sean desproporcionados con la fortuna y condición del causante; ni por los gastos de boda que no exceden de lo razonable; ni por los presentes de uso; ni por el seguro de vida que corresponde al heredero, pero sí por las primas pagadas por el causante al asegurador, hasta la concurrencia del premio cobrado por el asegurado. También se debe por lo empleado para establecer al coheredero o para el pago de sus deudas.", plainLanguageExplanation: "Establece el régimen de beneficios excluidos de la colación. No se debe colación por los gastos de alimentos; ni por los de asistencia médica por extraordinarios que sean; ni por los de educación y capacitación profesional o artística de los descendientes, excepto que sean desproporcionados con la fortuna y condición del causante; ni por l", practicalEffects: ['En la práctica, este artículo rige beneficios excluidos de la colación. No se debe colación por los gastos de alimentos; ni por los de asistencia médica por extraordinarios que sean; ni por los de educación y capacitación'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['beneficios', 'excluidos', 'colacin', 'articulo 2392'], segments: [], amendments: [] },
  { id: 'ccyc-art-2393', lawId: 'codigo-civil-comercial', number: '2393', order: 2393, title: "Perecimiento sin culpa", text: "Perecimiento sin culpa. No se debe colación por el bien que ha perecido sin culpa del donatario. Pero si éste ha percibido una indemnización, la debe por su importe.", plainLanguageExplanation: "Establece el régimen de perecimiento sin culpa. No se debe colación por el bien que ha perecido sin culpa del donatario.", practicalEffects: ['En la práctica, este artículo rige perecimiento sin culpa. No se debe colación por el bien que ha perecido sin culpa del donatario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['perecimiento', 'culpa', 'articulo 2393'], segments: [], amendments: [] },
  { id: 'ccyc-art-2394', lawId: 'codigo-civil-comercial', number: '2394', order: 2394, title: "Frutos", text: "Frutos. El heredero obligado a colacionar no debe los frutos de los bienes sujetos a colación, pero debe los intereses del valor colacionable desde la notificación de la demanda.", plainLanguageExplanation: "Establece el régimen de frutos. El heredero obligado a colacionar no debe los frutos de los bienes sujetos a colación, pero debe los intereses del valor colacionable desde la notificación de la demanda.", practicalEffects: ['En la práctica, este artículo rige frutos. El heredero obligado a colacionar no debe los frutos de los bienes sujetos a colación, pero debe los intereses del valor colacionable desde la notific'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['frutosarticulo 2394'], segments: [], amendments: [] },
  { id: 'ccyc-art-2395', lawId: 'codigo-civil-comercial', number: '2395', order: 2395, title: "Derecho de pedir la colación", text: "Derecho de pedir la colación. La colación sólo puede ser pedida por quien era coheredero presuntivo a la fecha de la donación. El cónyuge supérstite no puede pedir la colación de las donaciones hechas por el causante antes de contraer matrimonio.", plainLanguageExplanation: "Establece el régimen de derecho de pedir la colación. La colación sólo puede ser pedida por quien era coheredero presuntivo a la fecha de la donación.", practicalEffects: ['En la práctica, este artículo rige derecho de pedir la colación. La colación sólo puede ser pedida por quien era coheredero presuntivo a la fecha de la donación.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derecho', 'pedir', 'colacin', 'articulo 2395'], segments: [], amendments: [] },
  { id: 'ccyc-art-2396', lawId: 'codigo-civil-comercial', number: '2396', order: 2396, title: "Modo de hacer la colación", text: "Modo de hacer la colación. La colación se efectúa sumando el valor de la donación al de la masa hereditaria después de pagadas las deudas, y atribuyendo ese valor en el lote del donatario. CAPITULO 4 Colación de deudas", plainLanguageExplanation: "Establece el régimen de modo de hacer la colación. La colación se efectúa sumando el valor de la donación al de la masa hereditaria después de pagadas las deudas, y atribuyendo ese valor en el lote del donatario.", practicalEffects: ['En la práctica, este artículo rige modo de hacer la colación. La colación se efectúa sumando el valor de la donación al de la masa hereditaria después de pagadas las deudas, y atribuyendo ese valor en el lote del donatario.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modo', 'hacer', 'colacin', 'articulo 2396'], segments: [], amendments: [] },
  { id: 'ccyc-art-2397', lawId: 'codigo-civil-comercial', number: '2397', order: 2397, title: "Deudas que se colacionan", text: "Deudas que se colacionan. Se colacionan a la masa las deudas de uno de los coherederos en favor del causante que no fueron pagadas voluntariamente durante la indivisión, aunque sean de plazo no vencido al tiempo de la partición.", plainLanguageExplanation: "Establece el régimen de deudas que se colacionan. Se colacionan a la masa las deudas de uno de los coherederos en favor del causante que no fueron pagadas voluntariamente durante la indivisión, aunque sean de plazo no vencido al tiempo de la partición.", practicalEffects: ['En la práctica, este artículo rige deudas que se colacionan. Se colacionan a la masa las deudas de uno de los coherederos en favor del causante que no fueron pagadas voluntariamente durante la indivisión, aunque'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deudas', 'colacionan', 'articulo 2397'], segments: [], amendments: [] },
  { id: 'ccyc-art-2398', lawId: 'codigo-civil-comercial', number: '2398', order: 2398, title: "Suspensión de los derechos de los coherederos", text: "Suspensión de los derechos de los coherederos. Los coherederos no pueden exigir el pago antes de la partición.", plainLanguageExplanation: "Establece el régimen de suspensión de los derechos de los coherederos. Los coherederos no pueden exigir el pago antes de la partición.", practicalEffects: ['En la práctica, este artículo rige suspensión de los derechos de los coherederos. Los coherederos no pueden exigir el pago antes de la partición.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['suspensin', 'derechos', 'coherederos', 'articulo 2398'], segments: [], amendments: [] },
  { id: 'ccyc-art-2399', lawId: 'codigo-civil-comercial', number: '2399', order: 2399, title: "Deudas surgidas durante la indivisión", text: "Deudas surgidas durante la indivisión. La colación de deudas se aplica también a las sumas de las cuales un coheredero se hace deudor hacia los otros en ocasión de la indivisión, cuando el crédito es relativo a los bienes indivisos, excepto que los segundos perciban el pago antes de la partición.", plainLanguageExplanation: "Establece el régimen de deudas surgidas durante la indivisión. La colación de deudas se aplica también a las sumas de las cuales un coheredero se hace deudor hacia los otros en ocasión de la indivisión, cuando el crédito es relativo a los bienes indivisos, excepto que los segundos perciban el pago antes de la partición.", practicalEffects: ['En la práctica, este artículo rige deudas surgidas durante la indivisión. La colación de deudas se aplica también a las sumas de las cuales un coheredero se hace deudor hacia los otros en ocasión de la indivisión, cuando el'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['deudas', 'surgidas', 'durante', 'indivisin', 'articulo 2399'], segments: [], amendments: [] },
  { id: 'ccyc-art-2400', lawId: 'codigo-civil-comercial', number: '2400', order: 2400, title: "Intereses", text: "Intereses. Las sumas colacionables producen intereses desde la apertura de la sucesión si el coheredero era deudor del difunto, si no los devengaban ya con anterioridad, y desde el nacimiento de la deuda si ésta surge en ocasión de la indivisión.", plainLanguageExplanation: "Establece el régimen de intereses. Las sumas colacionables producen intereses desde la apertura de la sucesión si el coheredero era deudor del difunto, si no los devengaban ya con anterioridad, y desde el nacimiento de la deuda si ésta surge en ocasión de la indivisión.", practicalEffects: ['En la práctica, este artículo rige intereses. Las sumas colacionables producen intereses desde la apertura de la sucesión si el coheredero era deudor del difunto, si no los devengaban ya con anter'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['interesesarticulo 2400'], segments: [], amendments: [] },
  { id: 'ccyc-art-2401', lawId: 'codigo-civil-comercial', number: '2401', order: 2401, title: "Coheredero deudor y acreedor a la vez", text: "Coheredero deudor y acreedor a la vez. Si el coheredero deudor es a la vez acreedor, aunque su crédito no sea aún exigible al tiempo de la partición, hay compensación y sólo se colaciona el exceso de su deuda sobre su crédito.", plainLanguageExplanation: "Establece el régimen de coheredero deudor y acreedor a la vez. Si el coheredero deudor es a la vez acreedor, aunque su crédito no sea aún exigible al tiempo de la partición, hay compensación y sólo se colaciona el exceso de su deuda sobre su crédito.", practicalEffects: ['En la práctica, este artículo rige coheredero deudor y acreedor a la vez. Si el coheredero deudor es a la vez acreedor, aunque su crédito no sea aún exigible al tiempo de la partición, hay compensación y sólo se colaciona el'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['coheredero', 'deudor', 'acreedor', 'articulo 2401'], segments: [], amendments: [] },
  { id: 'ccyc-art-2402', lawId: 'codigo-civil-comercial', number: '2402', order: 2402, title: "Modo de hacer la colación", text: "Modo de hacer la colación. La colación de las deudas se hace deduciendo su importe de la porción del deudor. Si la exceden, debe pagarlas en las condiciones y plazos establecidos para la obligación. La imputación de la deuda al lote del coheredero deudor es oponible a sus acreedores. CAPITULO 5 Efectos de la partición", plainLanguageExplanation: "Establece el régimen de modo de hacer la colación. La colación de las deudas se hace deduciendo su importe de la porción del deudor.", practicalEffects: ['En la práctica, este artículo rige modo de hacer la colación. La colación de las deudas se hace deduciendo su importe de la porción del deudor.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['modo', 'hacer', 'colacin', 'articulo 2402'], segments: [], amendments: [] },
  { id: 'ccyc-art-2403', lawId: 'codigo-civil-comercial', number: '2403', order: 2403, title: "Efecto declarativo", text: "Efecto declarativo. La partición es declarativa y no traslativa de derechos. En razón de ella, se juzga que cada heredero sucede solo e inmediatamente al causante en los bienes comprendidos en su hijuela y en los que se le atribuyen por licitación, y que no tuvo derecho alguno en los que corresponden a sus coherederos. Igual solución se entiende respecto de los bienes atribuidos por cualquier otro acto que ha tenido por efecto hacer cesar la indivisión totalmente, o de manera parcial sólo respecto a ciertos bienes o ciertos herederos. Los actos válidamente otorgados respecto de algún bien de la masa hereditaria conservan sus efectos a consecuencia de la partición, sea quien sea el adjudicatario de los bienes que fueron objeto de esos actos.", plainLanguageExplanation: "Establece el régimen de efecto declarativo. La partición es declarativa y no traslativa de derechos.", practicalEffects: ['En la práctica, este artículo rige efecto declarativo. La partición es declarativa y no traslativa de derechos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['efecto', 'declarativo', 'articulo 2403'], segments: [], amendments: [] },
  { id: 'ccyc-art-2404', lawId: 'codigo-civil-comercial', number: '2404', order: 2404, title: "Evicción", text: "Evicción. En caso de evicción de los bienes adjudicados, o de sufrir el adjudicatario alguna turbación del derecho en el goce pacífico de aquéllos, o de las servidumbres en razón de causa anterior a la partición, cada uno de los herederos responde por la correspondiente indemnización en proporción a su parte, soportando el heredero vencido o perjudicado la parte que le toque. Si alguno de los herederos resulta insolvente, su contribución debe ser cubierta por todos los demás. Ninguno de los herederos puede excusar su responsabilidad por haber perecido los bienes adjudicados en la partición, aunque haya sido por caso fortuito.", plainLanguageExplanation: "Establece el régimen de evicción. En caso de evicción de los bienes adjudicados, o de sufrir el adjudicatario alguna turbación del derecho en el goce pacífico de aquéllos, o de las servidumbres en razón de causa anterior a la partición, cada uno de los herederos responde por la correspondiente indemnización en pr", practicalEffects: ['En la práctica, este artículo rige evicción. En caso de evicción de los bienes adjudicados, o de sufrir el adjudicatario alguna turbación del derecho en el goce pacífico de aquéllos, o de las ser'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['eviccinarticulo 2404'], segments: [], amendments: [] },
  { id: 'ccyc-art-2405', lawId: 'codigo-civil-comercial', number: '2405', order: 2405, title: "Extensión de la garantía", text: "Extensión de la garantía. La garantía de evicción se debe por el valor de los bienes al tiempo en que se produce. Si se trata de créditos, la garantía de evicción asegura su existencia y la solvencia del deudor al tiempo de la partición.", plainLanguageExplanation: "Establece el régimen de extensión de la garantía. La garantía de evicción se debe por el valor de los bienes al tiempo en que se produce.", practicalEffects: ['En la práctica, este artículo rige extensión de la garantía. La garantía de evicción se debe por el valor de los bienes al tiempo en que se produce.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['extensin', 'garanta', 'articulo 2405'], segments: [], amendments: [] },
  { id: 'ccyc-art-2406', lawId: 'codigo-civil-comercial', number: '2406', order: 2406, title: "Casos excluidos de la garantía", text: "Casos excluidos de la garantía. La garantía de evicción no tiene lugar cuando es expresamente excluida en el acto de partición respecto de un riesgo determinado; tampoco cuando la evicción se produce por culpa del coheredero que la sufre. El conocimiento por el adjudicatario al tiempo de la partición del peligro de evicción no excluye la garantía.", plainLanguageExplanation: "Establece el régimen de casos excluidos de la garantía. La garantía de evicción no tiene lugar cuando es expresamente excluida en el acto de partición respecto de un riesgo determinado; tampoco cuando la evicción se produce por culpa del coheredero que la sufre.", practicalEffects: ['En la práctica, este artículo rige casos excluidos de la garantía. La garantía de evicción no tiene lugar cuando es expresamente excluida en el acto de partición respecto de un riesgo determinado; tampoco cuando la ev'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'excluidos', 'garanta', 'articulo 2406'], segments: [], amendments: [] },
  { id: 'ccyc-art-2407', lawId: 'codigo-civil-comercial', number: '2407', order: 2407, title: "Defectos ocultos", text: "Defectos ocultos. Los coherederos se deben recíprocamente garantía de los defectos ocultos de los bienes adjudicados. CAPITULO 6 Nulidad y reforma de la partición", plainLanguageExplanation: "Establece el régimen de defectos ocultos. Los coherederos se deben recíprocamente garantía de los defectos ocultos de los bienes adjudicados.", practicalEffects: ['En la práctica, este artículo rige defectos ocultos. Los coherederos se deben recíprocamente garantía de los defectos ocultos de los bienes adjudicados.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['defectos', 'ocultos', 'articulo 2407'], segments: [], amendments: [] },
  { id: 'ccyc-art-2408', lawId: 'codigo-civil-comercial', number: '2408', order: 2408, title: "Causas de nulidad", text: "Causas de nulidad. La partición puede ser invalidada por las mismas causas que pueden serlo los actos jurídicos. El perjudicado puede solicitar la nulidad, o que se haga una partición complementaria o rectificativa, o la atribución de un complemento de su porción.", plainLanguageExplanation: "Establece el régimen de causas de nulidad. La partición puede ser invalidada por las mismas causas que pueden serlo los actos jurídicos.", practicalEffects: ['En la práctica, este artículo rige causas de nulidad. La partición puede ser invalidada por las mismas causas que pueden serlo los actos jurídicos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['causas', 'nulidad', 'articulo 2408'], segments: [], amendments: [] },
  { id: 'ccyc-art-2409', lawId: 'codigo-civil-comercial', number: '2409', order: 2409, title: "Otros casos de acción de complemento", text: "Otros casos de acción de complemento. El artículo 2408 se aplica a todo acto, cualquiera que sea su denominación, cuyo objeto sea hacer cesar la indivisión entre los coherederos, excepto que se trate de una cesión de derechos hereditarios entre coherederos en la que existe un álea expresada y aceptada.", plainLanguageExplanation: "Establece el régimen de otros casos de acción de complemento. El artículo 2408 se aplica a todo acto, cualquiera que sea su denominación, cuyo objeto sea hacer cesar la indivisión entre los coherederos, excepto que se trate de una cesión de derechos hereditarios entre coherederos en la que existe un álea expresada y aceptada.", practicalEffects: ['En la práctica, este artículo rige otros casos de acción de complemento. El artículo 2408 se aplica a todo acto, cualquiera que sea su denominación, cuyo objeto sea hacer cesar la indivisión entre los coherederos, excepto q'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['otros', 'casos', 'accin', 'complemento', 'articulo 2409'], segments: [], amendments: [] },
  { id: 'ccyc-art-2410', lawId: 'codigo-civil-comercial', number: '2410', order: 2410, title: "Casos en que no son admisibles las acciones", text: "Casos en que no son admisibles las acciones. Las acciones previstas en este Capítulo no son admisibles si el coheredero que las intenta enajena en todo o en parte su lote después de la cesación de la violencia, o del descubrimiento del dolo, el error o la lesión. CAPITULO 7 Partición por los ascendientes SECCION 1ª Disposiciones generales", plainLanguageExplanation: "Establece el régimen de casos en que no son admisibles las acciones. Las acciones previstas en este Capítulo no son admisibles si el coheredero que las intenta enajena en todo o en parte su lote después de la cesación de la violencia, o del descubrimiento del dolo, el error o la lesión.", practicalEffects: ['En la práctica, este artículo rige casos en que no son admisibles las acciones. Las acciones previstas en este Capítulo no son admisibles si el coheredero que las intenta enajena en todo o en parte su lote después de la cesación d'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['casos', 'admisibles', 'acciones', 'articulo 2410'], segments: [], amendments: [] },
  { id: 'ccyc-art-2411', lawId: 'codigo-civil-comercial', number: '2411', order: 2411, title: "Personas que pueden efectuarla", text: "Personas que pueden efectuarla. La persona que tiene descendientes puede hacer la partición de sus bienes entre ellos por donación o por testamento. Si es casada, la partición de los bienes propios debe incluir al cónyuge que conserva su vocación hereditaria. La partición de los gananciales sólo puede ser efectuada por donación, mediante acto conjunto de los cónyuges.", plainLanguageExplanation: "Establece el régimen de personas que pueden efectuarla. La persona que tiene descendientes puede hacer la partición de sus bienes entre ellos por donación o por testamento.", practicalEffects: ['En la práctica, este artículo rige personas que pueden efectuarla. La persona que tiene descendientes puede hacer la partición de sus bienes entre ellos por donación o por testamento.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['personas', 'pueden', 'efectuarla', 'articulo 2411'], segments: [], amendments: [] },
  { id: 'ccyc-art-2412', lawId: 'codigo-civil-comercial', number: '2412', order: 2412, title: "Bienes no incluidos", text: "Bienes no incluidos. Si la partición hecha por los ascendientes no comprende todos los bienes que dejan a su muerte, el resto se distribuye y divide según las reglas legales.", plainLanguageExplanation: "Establece el régimen de bienes no incluidos. Si la partición hecha por los ascendientes no comprende todos los bienes que dejan a su muerte, el resto se distribuye y divide según las reglas legales.", practicalEffects: ['En la práctica, este artículo rige bienes no incluidos. Si la partición hecha por los ascendientes no comprende todos los bienes que dejan a su muerte, el resto se distribuye y divide según las reglas legal'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['bienes', 'incluidos', 'articulo 2412'], segments: [], amendments: [] },
  { id: 'ccyc-art-2413', lawId: 'codigo-civil-comercial', number: '2413', order: 2413, title: "Colación", text: "Colación. Al hacer la partición, sea por donación o por testamento, el ascendiente debe colacionar a la masa el valor de los bienes que anteriormente haya donado y sean susceptibles de colación.", plainLanguageExplanation: "Establece el régimen de colación. Al hacer la partición, sea por donación o por testamento, el ascendiente debe colacionar a la masa el valor de los bienes que anteriormente haya donado y sean susceptibles de colación.", practicalEffects: ['En la práctica, este artículo rige colación. Al hacer la partición, sea por donación o por testamento, el ascendiente debe colacionar a la masa el valor de los bienes que anteriormente haya donad'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['colacinarticulo 2413'], segments: [], amendments: [] },
  { id: 'ccyc-art-2414', lawId: 'codigo-civil-comercial', number: '2414', order: 2414, title: "Mejora", text: "Mejora. En la partición, el ascendiente puede mejorar a alguno de sus descendientes o al cónyuge dentro de los límites de la porción disponible, pero debe manifestarlo expresamente. SECCION 2ª Partición por donación", plainLanguageExplanation: "Establece el régimen de mejora. En la partición, el ascendiente puede mejorar a alguno de sus descendientes o al cónyuge dentro de los límites de la porción disponible, pero debe manifestarlo expresamente.", practicalEffects: ['En la práctica, este artículo rige mejora. En la partición, el ascendiente puede mejorar a alguno de sus descendientes o al cónyuge dentro de los límites de la porción disponible, pero debe manifestarlo expresamente.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['mejoraarticulo 2414'], segments: [], amendments: [] },
  { id: 'ccyc-art-2415', lawId: 'codigo-civil-comercial', number: '2415', order: 2415, title: "Objeto", text: "Objeto. La partición por donación no puede tener por objeto bienes futuros. Puede ser hecha mediante actos separados si el ascendiente interviene en todos ellos.", plainLanguageExplanation: "Establece el régimen de objeto. La partición por donación no puede tener por objeto bienes futuros.", practicalEffects: ['En la práctica, este artículo rige objeto. La partición por donación no puede tener por objeto bienes futuros.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['objetoarticulo 2415'], segments: [], amendments: [] },
  { id: 'ccyc-art-2416', lawId: 'codigo-civil-comercial', number: '2416', order: 2416, title: "Derechos transmitidos", text: "Derechos transmitidos. El donante puede transmitir la plena propiedad de los bienes donados, o bien únicamente la nuda propiedad, reservándose el usufructo. También puede pactarse entre el donante y los donatarios una renta vitalicia en favor del primero.", plainLanguageExplanation: "Establece el régimen de derechos transmitidos. El donante puede transmitir la plena propiedad de los bienes donados, o bien únicamente la nuda propiedad, reservándose el usufructo.", practicalEffects: ['En la práctica, este artículo rige derechos transmitidos. El donante puede transmitir la plena propiedad de los bienes donados, o bien únicamente la nuda propiedad, reservándose el usufructo.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['derechos', 'transmitidos', 'articulo 2416'], segments: [], amendments: [] },
  { id: 'ccyc-art-2417', lawId: 'codigo-civil-comercial', number: '2417', order: 2417, title: "Acción de reducción", text: "Acción de reducción. El descendiente omitido en la partición por donación o nacido después de realizada ésta, y el que ha recibido un lote de valor inferior al correspondiente a su porción legítima, pueden ejercer la acción de reducción si a la apertura de la sucesión no existen otros bienes del causante suficientes para cubrirla.", plainLanguageExplanation: "Establece el régimen de acción de reducción. El descendiente omitido en la partición por donación o nacido después de realizada ésta, y el que ha recibido un lote de valor inferior al correspondiente a su porción legítima, pueden ejercer la acción de reducción si a la apertura de la sucesión no existen otros bienes del caus", practicalEffects: ['En la práctica, este artículo rige acción de reducción. El descendiente omitido en la partición por donación o nacido después de realizada ésta, y el que ha recibido un lote de valor inferior al correspondi'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['accin', 'reduccin', 'articulo 2417'], segments: [], amendments: [] },
  { id: 'ccyc-art-2418', lawId: 'codigo-civil-comercial', number: '2418', order: 2418, title: "Valor de los bienes", text: "Valor de los bienes. En todos los casos, para la colación y el cálculo de la legítima, se debe tener en cuenta el valor de los bienes al tiempo en que se hacen las donaciones, apreciado a valores constantes.", plainLanguageExplanation: "Establece el régimen de valor de los bienes. En todos los casos, para la colación y el cálculo de la legítima, se debe tener en cuenta el valor de los bienes al tiempo en que se hacen las donaciones, apreciado a valores constantes.", practicalEffects: ['En la práctica, este artículo rige valor de los bienes. En todos los casos, para la colación y el cálculo de la legítima, se debe tener en cuenta el valor de los bienes al tiempo en que se hacen las donacio'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['valor', 'bienes', 'articulo 2418'], segments: [], amendments: [] },
  { id: 'ccyc-art-2419', lawId: 'codigo-civil-comercial', number: '2419', order: 2419, title: "Garantía de evicción", text: "Garantía de evicción. Los donatarios se deben recíprocamente garantía de evicción de los bienes recibidos. La acción puede ser ejercida desde que la evicción se produce, aun antes de la muerte del causante.", plainLanguageExplanation: "Establece el régimen de garantía de evicción. Los donatarios se deben recíprocamente garantía de evicción de los bienes recibidos.", practicalEffects: ['En la práctica, este artículo rige garantía de evicción. Los donatarios se deben recíprocamente garantía de evicción de los bienes recibidos.'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['garanta', 'eviccin', 'articulo 2419'], segments: [], amendments: [] },
  { id: 'ccyc-art-2420', lawId: 'codigo-civil-comercial', number: '2420', order: 2420, title: "Revocación", text: "Revocación. La partición por donación puede ser revocada por el ascendiente, con relación a uno o más de los donatarios, en los casos en que se autoriza la revocación de las donaciones y cuando el donatario incurre en actos que justifican la exclusión de la herencia por indignidad. SECCION 3ª Partición por testamento", plainLanguageExplanation: "Establece el régimen de revocación. La partición por donación puede ser revocada por el ascendiente, con relación a uno o más de los donatarios, en los casos en que se autoriza la revocación de las donaciones y cuando el donatario incurre en actos que justifican la exclusión de la herencia por indignidad.", practicalEffects: ['En la práctica, este artículo rige revocación. La partición por donación puede ser revocada por el ascendiente, con relación a uno o más de los donatarios, en los casos en que se autoriza la revoca'], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: ['revocacinarticulo 2420'], segments: [], amendments: [] },
];
